(window.courseContentFiles = window.courseContentFiles || {})["000002/0003"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>document</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 7px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n      padding: 5px 7px;\n      border: 1px solid #d8e5d4;\n      border-radius: 9px;\n      background: #f4f9f2;\n    }\n    .audio-link-icon {\n      width: 26px;\n      height: 26px;\n      border: 1px solid #588157;\n      border-radius: 8px !important;\n      background: transparent;\n      color: #2f5d50;\n      cursor: pointer;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 26px;\n      padding: 0;\n      text-align: center;\n      font-size: 12px;\n      font-weight: 700;\n    }\n    .audio-link-icon img,\n    .audio-time {\n      display: none !important;\n    }\n    .audio-link-label {\n      max-width: 125px;\n      min-width: 0;\n      font-size: 0.82em;\n      font-weight: 700;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .audio-link-label:empty {\n      display: none;\n    }\n    .audio-progress {\n      width: 118px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-volume {\n      width: 44px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-progress,\n    .audio-volume {\n      height: 4px;\n      appearance: none;\n      -webkit-appearance: none;\n      background: transparent;\n    }\n    .audio-link-inline audio {\n      display: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Тема 9. Аортна инсуфициенция – етология, хемодинамика, физикална находка, дагноза и лечение.</h1><p>Аортната инсуфициенция е състояние, при което аортната клапа не се затваря плътно. Това води до <strong>регургитация</strong> на кръв от аортата обратно в лявата камера по време на диастола.</p><h3>Етиология</h3><p>За разлика от аортната стеноза (АС), АИ може да бъде резултат на много причини:</p><ul><li><strong>Болести на аортната клапа:</strong></li><ul><li>Ревматизъм (<strong>65-70%</strong>)</li><li>Сифилис (<strong>15-20%</strong>)</li><li>Атеросклеротична (<strong>7%</strong>)</li><li>Бактериалeн ендокардит (<strong>2%</strong>)</li><li>Инфекциозен ендокардит, ревматоиден артрит, анкилозиращ спондилит, лупус, болест на Райтер, артериит на Такайасу</li><li>Структурни дефекти (руптура на синус Валсалва), вродени клапни дисплазии</li></ul><li><strong>Болести на аортния корен:</strong></li><ul><li>Възпалителни (<strong>сифилис</strong>, болести на съединителната тъкан, болест на Бехтерев, на Райтер)</li><li>Прогресираща идиопатична аортна дилатация, ануло-аортна ектазия</li><li>Травматично разкъсване или спонтанна аортна дисекация</li></ul></ul><p><strong>Острата АИ</strong> най-често се дължи на:</p><ul><li>дисекация на асцендентната аорта.</li><li>Инфекциозен ендокардит.</li><li>Спонтанна руптура.</li><li>Пролапс на клапните платна.</li><li>Остра дехисценция на аортна клапна протеза.</li></ul><h3><strong></strong></h3><h3><strong>Хемодинамика</strong></h3><p>По време на диастола ЛК се пълни от две места: нормално от лявото предсърдие и допълнително от аортата. Това води до:</p><ol><li><strong>Дилатация и хипертрофия</strong> на лявата камера.</li><li>Постепенно развитие на митрална инсуфициенция (<strong>МИ</strong>).</li><li>Застой в белия дроб и пулмонална хипертония.</li><li>Десностранна дилатация и недостатъчност.</li></ol><h3>Патофизиология според вида на АИ</h3><p><strong><span class=\"editor-note\" data-note=\"При **високостепенната ****хронична ****компенсирана ****АИ **голямото количество регургитираща кръв натоварва лявата камера с обем, което води до увеличение на нейния краен диастолен обем (ТДО). За да се справи с този излишък, сърцето развива ексцентрична ЛК хипертрофия, позволявайки на камерата да изтласква голям тотален ударен обем, което от своя страна генерира голямо пулсово налягане.\" id=\"note-1777210765198-2\">Високостепенна хронична компенсирана</span>:</strong></p><ul><li>Голямо количество регургитираща кръв.</li><li>Увеличение на крайния диастолен обем (<strong>ТДО</strong>) на ЛК.</li><li><strong>Ексцентрична ЛК хипертрофия</strong>.</li><li>Голям тотален ударен обем и голямо пулсово налягане.</li></ul><p><strong><span class=\"editor-note\" data-note=\"Когато процесът премине във **високостепенна хронична декомпенсирана АИ**, механизмът на адаптация се изчерпва и се наблюдава абнормна дилатация на лявата камера. Налягането в нея в края на диастолата (ТДН) става патологично високо, докато помпената функция отслабва, което води до ниска фракция на изтласкване (ФИ) и прогресивна редукция на ударния обем (УО).\" id=\"note-1777210786828-3\">Високостепенна хронична декомпенсирана</span>:</strong></p><ul><li>Абнормна дилатация на ЛК.</li><li>Високо крайно диастолно налягане (<strong>ТДН</strong>) и ниска фракция на изтласкване (<strong>ФИ</strong>).</li><li>Редукция на ударния обем (<strong>УО</strong>).</li></ul><p><strong><span class=\"editor-note\" data-note=\"При **тежката остра АИ** ситуацията е критична, тъй като лявата камера няма време да се адаптира и се наблюдава само малко повишение на ТДО. Понеже камерата е &quot;твърда&quot; и недилатирана, прииждащата кръв предизвиква внезапно и силно повишено налягане в ЛК и лявото предсърдие, което бързо се предава назад към съдовете и води до белодробен застой или оток.\" id=\"note-1777210809317-4\">Тежка остра АИ</span>:</strong></p><ul><li>Малко повишение на ТДО, но силно повишено налягане в ЛК и лявото предсърдие.</li><li>Бързо развитие на <strong>белодробен застой или оток</strong>.</li></ul><h3>Клинична картина</h3><p><strong>Симптоматика\n</strong>Оплакванията са сходни с тези при аортна стеноза: лесна умора, задух, стенокардия, замайване и синкопи. Характерна добавка са симптомите на <strong>хиперкинетизъм</strong> – субективно усещане за пулсации в главата и шията.</p><p><strong>Оглед и периферни белези</strong></p><ul><li><strong>Общ вид:</strong> Болните са бледи, понякога с <span class=\"editor-note\" data-note=\"**Марфаноиден хабитус** е термин в медицината, който описва характерен тип телосложение, наподобяващ това при пациенти със **синдром на Марфан.**\n**Основни характеристики**\n- Висок ръст и слабо тяло\n- Дълги крайници\n- Дълги, тънки пръсти (арахнодактилия)\n- Размахът на ръцете често надвишава височината\n- Хипермобилност на ставите\n- Често – деформации на гръдния кош (фуниеобразен или килевиден)\n![Image](https://cdn.prod.website-files.com/60789a45beb6eb469601750e/633b27a2c920d622d357ea8e_ddb9vHy235dxmqhOkRb2KLXyy70CBE6X8I3ec3dtQiXUoTE7lLPvu0-r6JuydtyzqSEHZBSm0HmrrZ6A9Zdx7fdNRoZ2bCH_F0MVOzqv5SQTg3hXPRnk_eAQF5wGd-_Ks4vj_E0i359SUL39zp9lrlm5LXwtc2OFM2LUanTnYIuM4TB8Umoop_mPrg.jpeg &quot;width=100%&quot;).\" id=\"note-1777210948175-5\">Марфаноиден хабитус</span>.</li><li><strong>Скачащи каротиди:</strong> Видими силни пулсации на шийните артерии, съпроводени от:</li><ul><li><strong>Симптом на Мюсе:</strong> Синхронно поклащане на главата.</li><li><strong>Симптом на Мюлер:</strong> Пулсации на увулата.</li><li><strong>Капилярен пулс на Quinke:</strong> Ритмично пребледняване и зачервяване на нокътното легло при леко притискане.</li></ul><li><strong>Видими пулсации:</strong> Забелязват се по слепоочията, шията, слабините и югулума.</li></ul><h3>Физикално изследване</h3><ul><li><strong>Пулс на Коригън:</strong> Описва се като \"воден чук\" – бърз, висок, скачащ и голям (<em>pulsus celer, altus, saliens, magnus</em>).</li><li><strong>Артериално налягане:</strong> Голяма систолно-диастолна разлика.</li><li><strong>Палпация и перкусия:</strong> Сърдечният удар е изместен наляво и надолу, разширен и хипердинамичен. Перкуторно се установява разширение на лявата камера.</li></ul><h3>Аускултация на сърцето</h3><ul><li><strong>Диастолен шум:</strong> Основен белег. </li><ul><li>Тих, аспиративен (духащ), разпространява се отгоре-дясно надолу по левия ръб на стернума към върха.</li><li>Чува се най-добре в <strong>III-IV междуребрие</strong> вляво от стернума (точка на Ерб).</li><li>Най-ясно се долавя, когато пациентът е в <strong>седнало положение</strong>.</li></ul><li><strong>Шум на Аустин-Флинт:</strong> Диастолен шум на сърдечния връх, имитиращ митрална стеноза. Дължи се на „релативна“ стеноза, тъй като връщащата се аортна кръв притиска предното митрално платно.</li><li><strong>Сърдечни тонове:</strong> I тон обикновено не е променен, докато II тон е нормален или отслабен. </li><li><strong>Систолен шум:</strong> Често се чува на аортното място поради деформиран отвор, създаващ турбуленция, или съпътстваща стеноза.</li></ul><h3>Аускултация на периферни артерии</h3><p>При АИ се наблюдават специфични феномени над големите съдове (брахиална, радиална, феморална артерия) поради големия ударен обем:</p><ul><li><strong>Двоен тон на Траубе:</strong> \n<p>Чуват се т.нар. „пистолетни“ тонове – високочестотни систолен и диастолен тон, които се установяват без притискане на съда (най-често над a. femoralis). Дължат се на рязкото разтягане и спадане на артериалната стена при голям ударен обем и широк пулсов натиск.</p><br></li><li><strong>Двоен шум на Дюрозие:</strong> \nУстановява се при <strong>компресия на артерията</strong> (обикновено a. femoralis) със стетоскоп. В зависимост от мястото на притискане спрямо аускултаторната точка се чуват два различни шума:</li></ul><ul><ul><li><p><strong>Систолен шум</strong> – при притискане с пръст проксимално (по-близо до сърцето).</p></li><li><p><strong>Диастолен шум</strong> – при притискане с пръст дистално (по-далеч от сърцето).</p></li></ul></ul><h3>Изследвания</h3><ul><li><strong>Рентгенография на сърцето (във фас):</strong> Установява се т. нар. <strong>аортна конфигурация</strong> — разширена лява камера, ясно изпъкваща талия на сърцето, разширение на възходящата аорта и аортното копче.</li><li><strong>ЕКГ:</strong> Показва ляво отклонение на електрическата ос, данни за <strong>хипертрофия и обемно обременяване</strong> на лявата камера. Могат да се регистрират неспецифични ST-T промени и проводни нарушения.</li><li><strong>ЕхоКГ:</strong></li><ul><li><strong>Цветен Доплер:</strong> Най-добре визуализира регургитационния джет; степента се определя полуколичествено по неговата големина.</li><li><strong>CW Doppler:</strong> Степента се определя по децелерационното време.</li></ul><li><strong>Ангиография:</strong> Позволява полуколичествено определяне на степента на порока (от I до IV степен).</li></ul><h3>Степени на тежест</h3><ul><li><strong>Лека:</strong> Протича асимптомно или с чувство за прекордиални пулсации. Пулсът, артериалното налягане (АН) и ЕКГ са непроменени; ЛК е с нормални или леко увеличени размери.</li><li><strong>Средностепенна:</strong> Проявява се с диспнея и ангина. Наблюдават се увеличена амплитуда на АН, повдигащ сърдечен удар и типичният <em>pulsus celer et altus</em>. ЕКГ показва ЛК хипертрофия, а ЕхоКГ — дилатирана лява камера.</li><li><strong>Високостепенна:</strong> Симптоми на диспнея, ортопнея, палпитации и тахикардия в покой. Рентгенографията показва аортна конфигурация и белези на застой; налице са силно дилатирана ЛК и хиперкинетизъм.</li></ul><h3>Диференциална диагноза</h3><p>Диференциалната диагноза се провежда в две основни насоки:</p><ol><li><strong>Етиологична диагноза:</strong> Цели уточняване на причината за порока — ревматизъм, атеросклероза, луес (сифилис) или инфекциозен ендокардит.</li><li><strong>По отношение на диастолните шумове:</strong> Необходимо е да се различат:</li><ul><li><strong>Пулмонална инсуфициенция</strong> (шум на Graham-Steell).</li><li><strong>Митрална стеноза</strong> (преди всичко поради приликата с шума на Аустин-Флинт).</li></ul></ol><h3>Лечение</h3><h4>1. Консервативно лечение</h4><ul><li><strong>Проследяване:</strong> Асимптомни пациенти с лека или умерена АИ подлежат на клинично и ЕхоКГ проследяване на всеки 12 или 24 месеца.</li><li><strong>Режим:</strong> Ограничение на тежкото физическо натоварване при умерена към тежка АИ.</li><li><strong>Профилактика:</strong> Задължителна профилактика на инфекциозен ендокардит (ИЕ).</li><li><strong>Медикаментозна терапия:</strong> </li><ul><li>Сърдечната недостатъчност се лекува по общите правила (диуретици, дигиталис, АСЕ инхибитори).</li><li><strong>Важно:</strong> Брадикардията не е желателна, тъй като удължаването на диастолата увеличава регургитацията. Поради това бета-блокерите трябва да се избягват.</li></ul></ul><h4>2. Хирургично лечение (Клапно протезиране)</h4><p>Хирургичната намеса е индицирана при:</p><ul><li><strong>Хронична АИ III-IV степен</strong> <p>и симптоматична CH II, III или IV фк (по NYHA).</p></li><li><strong>Асимптомна хронична АИ (II, III степен)</strong>, но с данни за систолна дисфункция на ЛК в покой:</li><ul><li>Фракция на изтласкване (<strong>ФИ</strong>) &lt; 55%</li><li>Краен диастолен размер (<strong>ТДР</strong>) &gt; 75 mm</li><li>Краен систолен размер (<strong>ТСР</strong>) &gt; 55 mm</li></ul></ul><p><strong>Забележка:</strong> При заболявания на аортния корен се налага хирургично лечение както на възходящата аорта, така и клапно протезиране (често чрез поставяне на комбинирана съдова протеза с клапа).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 10. Аортна стеноза – етиология, хемодинамика, физикална находка, диагноза и лечение.</h1><h3><strong>Определение</strong></h3><p>Аортната клапна стеноза представлява стеснение на аортния клапен отвор, което затруднява изтласкването на кръвта от лявата камера (ЛК) в аортата. Обструкцията може да бъде локализирана на три нива: клапно (най-често), надклапно и подклапно ниво (например при обструктивна хипертрофична кардиомиопатия).</p><h3><strong>Етиология</strong></h3><p>АС бива вродена и придобита:</p><ul><li><strong>Вродена:</strong> Деформации като уни-, би- или трикуспидна клапа. <strong>Бикуспидната клапа</strong> е най-честата причина, често съчетана с дилатация на асцендентната аорта. <p>Турбулентният кръвоток води до травматизиране на платната, последвано от фиброза, ригидност и калцификация, със стеснение на аортния отвор и клинична изява между 40–70 г</p><p>.</p></li><li><strong>Придобита:</strong> Основната причина е дегенеративната клапна болест, следвана от ревматизъм (все по-рядко).</li><li><strong>Площ на отвора:</strong> Нормалната клапа е 3.0 - 3.5 см<sup>2</sup>. При АС тя намалява под 2 см<sup>2</sup>, като може да достигне критични стойности под 0.5 см<sup>2</sup>.</li></ul><h3><strong>Хемодинамика</strong></h3><p>Стеснението на аортната клапа създава градиент между ЛК и аортата (ЛК систолно налягане е по-високо от аортното).</p><ol><li><strong>ЛК хипертрофия:</strong> Лявата камера е подложена на систолно обременяване и хипертрофира, за да поддържа налягането и да нормализира стенния стрес.</li><li><strong>Диастолна дисфункция:</strong> Намален къмплайънс на ЛК води до нарушено пълнене и дилатация на лявото предсърдие (ЛП).</li><li><strong>Кислороден дисбаланс:</strong> Несъответствие между повишената кислородна консумация на хипертрофиралия миокард и кислородната доставка.</li><li><strong>Сърдечен дебит:</strong> Намаленият минутен обем води до <strong>синкоп</strong>. При тежка аортна стеноза ударният обем не може да се увеличи адекватно, а при критична аортна стеноза сърдечният дебит е фиксиран.</li><li><strong>Късен стадий:</strong> <strong>Дилатация </strong>на лявата камера, свързана с неблагоприятна прогноза.</li></ol><h3><strong>Класификация според тежестта</strong></h3><p style=\"font-weight: bold\"><strong>Класификация на аортна стеноза</strong></p><ul><li><strong>Лека</strong>: площ &gt; 1.5 cm<sup>2</sup>; среден градиент &lt; 20 mmHg; максимален &lt; 50 mmHg</li><li><strong>Умерена</strong>: площ 1.0–1.5 cm<sup>2</sup>; среден градиент 20–39 mmHg; максимален 50–75 mmHg</li><li><strong>Тежка</strong>: площ &lt; 1.0 cm<sup>2</sup>; среден градиент &gt; 40 mmHg; максимален &gt; 75 mmHg</li><li><strong>Критична</strong>: площ &lt; 0.8 cm<sup>2</sup>; максимален градиент &gt; 75 mmHg</li></ul><h3><strong>Клинична картина</strong></h3><p>Основните симптоми са четири: <strong>синкоп</strong> при физически усилия, <strong>стенокардия</strong>, <strong>задух</strong> и <strong>сърцебиене</strong>.</p><p><strong>Обективно изследване:</strong></p><ul><li><strong>Външен вид:</strong> Блед цвят на лицето и забавена сърдечна дейност.</li><li><strong>Пулс:</strong> Малък (<strong>Pulsus Parvus</strong>) и бавно нарастващ (<strong>Pulsus Tardus</strong>).</li><li><strong>Палпация:</strong> Изместен надолу и наляво сърдечен удар (повдигащ тип), поради хипертрофията. <p>На мястото на аортата на основата се палпира систоличен </p><p><strong>фремисман</strong></p>.</li><li><strong>Аускултация:&nbsp;<button type=\"button\" class=\"audio-link-icon\" aria-label=\"Play audio\" title=\"Play audio\" style=\"border-radius: 8px !important\">▶</button><input class=\"audio-progress\" type=\"range\" min=\"0\" max=\"1000\" aria-label=\"Audio position\"><input class=\"audio-volume\" type=\"range\" min=\"0\" max=\"1\" step=\"0.01\" aria-label=\"Audio volume\"><audio preload=\"metadata\" src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-19/%D0%90%D0%BE%D1%80%D1%82%D0%BD%D0%B0%20%D1%81%D1%82%D0%B5%D0%BD%D0%BE%D0%B7%D0%B0.mp3\"></audio><br></strong></li><ul><li><strong>Систоличен шум:</strong> Груб, стържещ, с ромбовиден характер. Разпространява се към каротидите. Започва след отварянето на клапата, <p>усилва се и след това намалява дескресчендо и завършва пред II тон.</p></li><li><strong>Втори тон:</strong> Отслабена до липсваща аортна съставка.</li><li>Възможен <strong>ранен систолен клик на изтласкване</strong>.</li></ul></ul><h3>Диагноза</h3><ul><li><strong>Рентгеново изследване:</strong> Наблюдава се <strong>заоблена лява камера </strong>(ЛК) и връх, както и <strong>изпъкване на проксималната част на асцендентната аорта </strong>(поради постстенотично разширение). След 50-годишна възраст често се виждат калцификации по клапата. При сърдечна недостатъчност сърцето приема типична „аортна конфигурация“.</li><li><strong>ЕКГ:</strong> Белези за хипертрофия и обременяване на ЛК – високи R-зъбци и негативни Т-вълни в отвеждания I, aVL, V5-6, както и дълбоки S-зъбци в V1-2.</li></ul><ul><li><strong>Сфингмограма (а. каротис):</strong> Бавно възкачваща се част (анакрота), назъбена като „гребен на петел“, с удължено време на изтласкване.</li><li><strong>ЕхоКГ:</strong> Основен метод. Едноразмерната ЕхоКГ показва задебеляване на платната и стеснение на отвора. Двуразмерната ЕхоКГ и Доплер изследването определят градиента на налягането, наличието на калцификации и точната степен на стенозата.</li><li><strong>Сърдечна катетеризация и аортография:</strong> Използват се за хемодинамична оценка и за изключване на съпътстваща коронарна болест преди операция. Аортографията дава информация за размера на аортата и евентуална аортна недостатъчност.</li></ul><blockquote><p>Диагнозата АС се поставя въз основа на характерната аускултаторна находка, анамнезата за синкопални явления, стенокардия и левостранна слабост в напредналия стадий, ЕхоКГ критерии.</p></blockquote><h3>Диференциална диагноза</h3><p>АС трябва да се различи от:</p><ol><li><strong>Надклапна стеноза:</strong> Характеризира се с разлика в кръвното налягане на двете ръце (над 20 mmHg), умствено изоставане и типично „лице на фея“.</li><li><strong>Пулмонална стеноза:</strong> Шумът е вляво от стернума, има дясно сърдечно обременяване и намален кръвоток в белите дробове (олигемия).</li><li><strong>Митрална инсуфициенция:</strong> Шумът започва веднага от първи тон, върви декресчендо и се разпространява към аксилата.</li><li><strong>Вроден септатал дефект (ВРД):</strong> Шумът е локализиран по-ниско (IV междуребрие вляво) и се открива в ранна детска възраст.</li></ol><h3>Естествена еволюция и прогноза</h3><p>Средната продължителност на живота е 50-60 години. Характерен е дълъг асимптомен (латентен) период. Появи ли се веднъж сърдечна недостатъчност, тя се лекува се отсранява трудно и бързо рецидивира. Рисковете включват инфекциозен ендокардит, аритмии и внезапна сърдечна смърт (синдром на Адам-Стокс).</p><h3>Лечение</h3><p>Консервативното лечение на аортната стеноза се състои в потискане на ревматичните процеси, лечение на сърдечната левостранна недостатъчност, стенокардиите пристъпи и синкопалните явления чрез премахване на усилията, както и профилактика на <strong>инфекциозен ендокардит (ИЕ)</strong>.</p><p><strong>Лека към средна АС - асимптоматична:</strong></p><ul><li>Проследяване (ехокардиографски): лека АС – на 2 години; умерена – на 1 година; тежка – на 6 месеца.</li><li>Профилактика на ИЕ и контрол на рисковите фактори (антихипертензивно, липидопонижаващо и антиаритмично лечение).</li><li>Изявата на <strong>предсърдно мъждене</strong> може да предизвика остро хемодинамично влошаване поради загубата на предсърдната систола.</li><li><strong>Дехидратацията </strong>може да доведе до тежка хипотония, затова е необходимо внимателно приложение на <strong>диуретици</strong>. Вазодилататорите също трябва да се използват с внимание.</li><li>Обучение на пациента.</li></ul><p><strong>Хирургично и интервенционално лечение:</strong></p><ul><li>Хирургично лечение: аортно клапно протезиране (<strong>AVR</strong>) с механична или биологична протеза.</li><li><strong>Аортна балонна валвулопластика</strong>: временно решение поради висок процент на <strong>рестеноза</strong>.</li><li><strong>TAVR</strong>: транскатетърно аортно клапно протезиране при пациенти с висок или интермедиерен хирургичен риск.</li></ul><h3>Индикации за хирургично лечение</h3><ul><li>Симптоматични пациенти с <strong>тежка степен АС</strong>.</li><li>Болни с тежка АС, които се подлагат на аортно-коронарен байпас, хирургия на аортата или други клапи.</li><li>Болни с умерена АС, които се подлагат на аортно-коронарен байпас или друга сърдечна хирургия.</li><li>Асимптоматични пациенти с тежка АС и наличие на:</li><ul><li><strong>ЛК дисфункция</strong>&nbsp;</li><li>Абнормен отговор (хипотония) при обременяване.</li></ul></ul><h3>Прогноза</h3><p>Прогнозата е по-благоприятна в сравнение с другите пороци. Рискови фактори за висока смъртност са висок <strong><span class=\"editor-note\" data-note=\"Класификацията **NYHA** (New York Heart Association) е златен стандарт в медицината за оценка на тежестта на сърдечната недостатъчност. Тя не се базира на изследвания, а единствено на **функционалния капацитет** на пациента.\n---\n| Клас | Физическа активност | Симптоми (задух, умора) |\n| :--- | :--- | :--- |\n| **I** | Без ограничения | Липсват при обичайни усилия |\n| **II** | Леки ограничения | Появяват се при обичайни усилия |\n| **III** | Значителни ограничения | Появяват се при минимални усилия |\n| **IV** | Пълно ограничение | Налични дори в покой |\" id=\"note-1777206411972-1\">NYHA клас</span></strong>, наличие на<strong> ЛК дисфункция</strong>, <strong>напреднала възрас</strong>т и <strong>съпътстваща ИБС</strong>. След настъпване на <strong>сърдечната недостатъчност</strong> прогнозата рязко се влошава.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 11. Митрална инсуфициенция – етиология, хемодинамика, физикална находка, диагноза и лечение</h1><p>Начало</p><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 12. Митрална стеноза – етиология, хемодинамика, физикална находка, диагноза и лечение.</h1><p><strong>Митралната стеноза (МС)</strong> представлява стеснение на митралния клапен отвор под <strong>3 cm²</strong>, което затруднява преминаването на кръвта по време на диастола от <strong>лявото предсърдие</strong> към <strong>лявата камера</strong>.</p><h2>Етиология</h2><p>Най-честата причина е <strong>ревматизмът</strong>, но с намаляване на честотата му нараства делът на <strong>дегенеративната митрална стеноза</strong>.</p><h2>Патоанатомия</h2><p>Могат да бъдат засегнати различни структури на митралната клапа. Най-често се засягат <strong>комисурите</strong> — комисурен тип. По-рядко се засягат <strong>хордите</strong>, клапните платна или се развива смесен тип.</p><h2>Хемодинамика</h2><p><strong>Митралната стеноза</strong> създава механична пречка за пълненето на <strong>лявата камера</strong> по време на диастола. В резултат се развиват две основни промени:</p><ul><li>патологичен градиент на налягането между <strong>лявото предсърдие</strong> и <strong>лявата камера</strong>;</li><li>намаляване на <strong>сърдечния минутен обем</strong>.</li></ul><p>Повишеното налягане в лявото предсърдие се предава ретроградно към белодробните вени, белодробните капиляри и белодробната артерия. Така се развива <strong>пулмонална хипертония</strong>.</p><p><span class=\"editor-note\" data-note=\"Механизмите отразяват последователното развитие на **пулмонална хипертония** при митрална стеноза.\n**1.** **Пасивно ретроградно предаване на налягането** При митрална стеноза се затруднява диастолното преминаване на кръвта от **лявото предсърдие** към **лявата камера**. Това води до повишаване на налягането в лявото предсърдие, което се предава ретроградно към **белодробните вени**, **белодробните капиляри** и впоследствие към **белодробната артерия**. В този ранен етап пулмоналната хипертония е предимно пасивна и застойна.\n**2.** **Рефлекторен спазъм на белодробните артериоли** Продължителното повишено налягане в белодробното венозно и капилярно русло предизвиква вазоконстрикция на белодробните артериоли. Този спазъм увеличава съдовото съпротивление в малкия кръг и допълнително повишава налягането в белодробната артерия.\n**3. ****Структурно стеснение на белодробните артериоли — „втора бариера“** При дълготрайна пулмонална хипертония настъпват трайни морфологични промени в стените на белодробните артериоли: **хипертрофия на медията**, **ендотелна пролиферация** и **фиброза на съдовата стена**. Това води до анатомично стеснение на лумена и фиксиране на пулмоналната хипертония. Тези промени се означават като **„втора бариера“**, защото към първичната пречка на ниво митрална клапа се добавя вторична съдова пречка в белодробното кръвообращение.\" id=\"note-1778446067091-0\">Механизмите са</span>:</p><ol><li><strong>Пасивно ретроградно предаване</strong> на повишеното налягане от лявото предсърдие към белодробната венозна мрежа, белодробните капиляри и белодробната артерия.</li><li><strong>Спазъм на белодробните артериоли</strong>, който допълнително повишава съпротивлението в малкия кръг.</li><li><strong>Анатомично стеснение на артериолите</strong> вследствие на хипертрофия на медията, ендотелна пролиферация и фиброза на съдовата стена — т.нар. <strong>„втора бариера“</strong>.</li></ol><p>„Втората бариера“ води до фиксиране и необратимост на пулмоналната хипертония.</p><p>Постепенно пулмоналната хипертония натоварва <strong>дясната камера</strong>, която първо хипертрофира, след това дилатира и декомпенсира. Разширява се и дясното предсърдие, развива се <strong>релативна трикуспидална инсуфициенция</strong>, последвана от хепатомегалия, периферни и висцерални отоци — белези на <strong>десностранна сърдечна декомпенсация</strong>.</p><p>Намаленият митрален клапен отвор ограничава минутния обем на сърцето, което води до <strong>лесна умора</strong>, периферна цианоза и хипоперфузия на органите.</p><h3>Степени</h3><ul><li><strong>Лека митрална стеноза</strong> — над <strong>1.5 cm<sup>2</sup></strong></li><li><strong>Средностепенна митрална стеноза</strong> — <strong>1–1.5 cm<sup>2</sup></strong></li><li><strong>Тежка митрална стеноза</strong> — под <strong>1 cm<sup>2</sup></strong></li></ul><h2>Клиника</h2><p>Симптоматиката при <strong>митрална стеноза</strong> зависи от степента и давността на порока. В началото оплакванията се появяват при физическо усилие, а при напредване — и в покой.</p><p>Най-ранни и характерни симптоми са <strong>задух</strong>, лесна умора, сърцебиене и суха кашлица. <strong>Диспнеята</strong> се дължи на венокапилярна белодробна хипертония и повишена ригидност на белите дробове. По-късно може да премине в <strong>ортопнея</strong>. Кашлицата може да бъде суха или с <strong>кръвохрак</strong>, което понякога създава диагностични затруднения. Възможни са и болки в сърдечната област, свързани с белодробната хипертония.</p><h3>Оглед и палпация</h3><p>При оглед се установява <strong>периферна цианоза</strong> по устните, бузите и ръцете, дължаща се на намален сърдечен дебит и периферен вазоспазъм. Характерен е <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-10/text-editor-images/2026/05/1778446354314-image.png &quot;width=100%&quot;)\" id=\"note-1778446356026-1\">facies mitralis</span></strong> — синьо-червено оцветяване на бузите с телеангиектазии и цианоза на устните.</p><p>Сърдечният удар обикновено не се палпира. При развита деснокамерна хипертрофия могат да се палпират разлети пулсации в III–IV междуребрие до стернума. Често се установява <strong>пресистолен или диастолен фремисман</strong>.</p><h3>Аускултация</h3><p>Аускултацията е решаваща за диагнозата. Често болните са в <strong>предсърдно мъждене</strong>, с аритмична сърдечна дейност.</p><p>Характерни са <strong>акцентуиран I тон</strong>, акцентуиран и раздвоен <strong>II тон</strong> при пулмонална хипертония, както и <strong>тон на отваряне на митралната клапа (ТОМ)</strong> след II тон.</p><p>Най-характерният аускултаторен белег е <strong>нискочестотният диастолен шум</strong> след ТОМ, наподобяващ „котешко мъркане“. Продължителността му корелира с тежестта на стенозата. При синусов ритъм шумът завършва с <strong>пресистолно усилване</strong>, дължащо се на предсърдната контракция; при предсърдно мъждене това усилване изчезва.</p><p>Допълнително могат да се чуят <strong>шум на Graham Steell</strong> при релативна пулмонална инсуфициенция и шум от релативна трикуспидална инсуфициенция при дилатация на дясната камера.</p><h3><span style=\"color: rgb(112, 48, 160)\">ЕКГ</span></h3><p>ЕКГ находката зависи от стадия и тежестта на митралната стеноза. Характерна е <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-10/text-editor-images/2026/05/1778446490666-image.png &quot;width=100%&quot;)\" id=\"note-1778446491789-2\">P-mitrale</span></strong> — разширена над 0.11 s и двугърба P-вълна в I и II отвеждане.</p><p>С прогресията се появяват данни за <strong>деснокамерно обременяване</strong> и десен тип ЕКГ. Нерядко се установява <strong>предсърдно мъждене</strong>.</p><h3>Рентгенография</h3><p>Рентгенологично се вижда <strong>митрална конфигурация</strong> — изглаждане на сърдечната талия поради разширен конус на белодробната артерия.</p><p>Във II косо положение разширеното ляво предсърдие изпъква в ретрокардиалното пространство и при контрастиране може да измества или притиска хранопровода. Рентгенографията дава данни и за <strong>пулмонална венозна хипертония</strong>.</p><h3>Ехокардиография</h3><p><strong>Ехокардиографията</strong> е най-важният съвременен неинвазивен метод. Чрез нея се оценяват степента на стенозата, клапният и подклапният апарат, наличие на тромб в лявото предсърдие, пулмоналното налягане и състоянието на дясната сърдечна половина.</p><p>Площта на митралната клапа се определя чрез <strong>планиметрия</strong> или чрез <strong>CW Doppler</strong>. В клиничната практика често се предпочита <strong>CW Doppler</strong>, като основен показател е <strong>pressure half-time (PHT)</strong>, чрез който автоматично се изчислява площта на клапния отвор.</p><p><strong>Трансезофагеалната ехокардиография (TEE)</strong> позволява по-точна оценка на клапните структури, калцинозата и наличие на тромб в лявото предсърдие, особено преди <strong>балонна валвулопластика</strong>.</p><p><strong>Стрес ехокардиография</strong> се използва за по-точна оценка на симптоматиката и показанията за оперативно лечение.</p><h3>Сърдечна катетеризация</h3><p>Провежда се предоперативно, основно за оценка на <strong>коронарните артерии</strong>.</p><h2>Диференциална диагноза</h2><p>Митралната стеноза трябва да се различава от:</p><ul><li><strong>Аортна инсуфициенция</strong> с диастолен шум на <strong>Austin-Flint</strong> на върха. Той се дължи на изместване на предното митрално платно от голямата аортна регургитация в диастола, но <strong>не се съпровожда от ТМО</strong> и акцентуиран I тон.</li><li><strong>Тумор в лявото предсърдие</strong>.</li><li><strong>Синдром на Lutembacher</strong> — митрална стеноза + междупредсърден дефект.</li><li><strong>Трикуспидална стеноза</strong>.</li><li><strong>Хиперкинетични състояния</strong> с наличие на III тон.</li></ul><h2>Лечение на митрална стеноза</h2><p>В компенсиран стадий — <strong>I–II функционален клас</strong> — митралната стеноза обикновено не изисква медикаментозно лечение. Основни мерки са <strong>ограничаване на физическата активност</strong> и профилактика на <strong>инфекциозен ендокардит</strong>.</p><p>Консервативното лечение е насочено главно към усложненията: белодробен застой, кардиална астма, белодробен оток, сърдечна недостатъчност, предсърдно мъждене и тромбоемболии.</p><p>При белодробен застой се препоръчват ограничаване на физическото натоварване, намален прием на сол и <strong>диуретици</strong>. Могат да се използват и <strong>β-блокери</strong>. <strong>Дигиталисовите глюкозиди</strong> се избягват при синусов ритъм, но са показани при <strong>предсърдно мъждене</strong> за контрол на камерната честота.</p><p>При често рецидивиращо предсърдно мъждене се използват антиаритмични средства като ритмонорм, соталол, кордарон и др. При хронично предсърдно мъждене сърдечната честота трябва да се поддържа около <strong>60–70/min</strong>, за да се осигури по-добро диастолно пълнене.</p><p><strong>Продължителна антикоагулантна терапия</strong> е необходима при:</p><ul><li>преживян емболизъм;</li><li>тромб в лявото предсърдие, дори при синусов ритъм;</li><li>предсърдно мъждене;</li><li>клапно протезиране.</li></ul><p>Средство на избор са <strong>витамин К антагонистите</strong>. <strong>НОАК</strong> не са подходящи.</p><h3>Оперативно лечение</h3><p>На оперативно лечение — най-често <strong>клапно протезиране</strong> — подлежат пациенти с тежка митрална стеноза с площ под <strong>1 cm<sup>2</sup></strong>. То се препоръчва и при клинично изявена умерено тежка стеноза с площ под <strong>1.5 cm<sup>2</sup></strong>, ако симптомите са свързани с митралната стеноза.</p><p>Възможна е и <strong>комисуротомия на отворено сърце</strong>. При подходяща клапна анатомия алтернатива е <strong>балонна валвулопластика</strong>.</p><p>Противопоказания за балонна валвулопластика са <strong>тромб в лявото предсърдие</strong>, значима митрална инсуфициенция, тежка калциноза, коронарна болест, изискваща байпас хирургия, и лека митрална стеноза с площ над <strong>1.5 cm<sup>2</sup></strong>.</p><br><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 13. Хипертонична болест - класификация, етиология, патогенеза, степени</h1><p>Артериалната хипертония (АХ) при лица над 18-годишна възраст представлява трайно повишаване на артериалното налягане (АН). За диагностични граници се приемат стойности на <strong>систолното АН ≥ 140 mmHg</strong> и/или <strong>диастолното АН ≥ 90 mmHg</strong>. Диагнозата се поставя след измерване в три различни прегледа в рамките на няколко седмици. Стандарт за класификация е т.нар. <strong>офисно АН</strong> (измерено в кабинета). \n<strong><span class=\"editor-note\" data-note=\"## Измерване на артериалното налягане\nЗа коректни резултати са необходими следните условия:\n- **Положение:** Пациентът трябва да е седнал, с ръка на нивото на сърцето.\n- **Техника:** Маншетата се поставя на **2 см над лакътната яма**. Напомпва се до **20 mmHg** над очакваната систола и се отпуска бавно (**3 mmHg/s**).\n- **Отчитане:** Систолното АН се фиксира при появата на първия тон, а диастолното – при изчезването на тоновете.\n**Динамика на АН:\n**Артериалното налягане е променлива величина, подвластна на:\n- **Краткотрайни колебания:** Дишане, сърдечна честота и външни фактори (стрес, кофеин, алкохол, тютюнопушене, студ).\n- **Денонощен ритъм:** Повишаване в ранните сутрешни часове и физиологичен спад по време на сън (след полунощ).\" id=\"note-1777402044959-0\"><span style=\"color: rgb(112, 48, 160)\">Измерване на артериално налягане</span></span></strong>. \n<strong><span class=\"editor-note\" data-note=\"## Ключови понятия\n* **Амбулаторно (24-часово) мониториране:** Осигурява по-висока прогностична стойност. Прилага се при: * Значителна вариабилност на АН. * Резистентност към терапията. * Съмнение за хипотонични епизоди. * Сънна апнея или риск от прееклампсия при бременни.\n* **Домашно измерване:** Ангажира пациента и подобрява контрола. Препоръчва се използването на апарати за предмишница.\n* **Хипертония на „бялата престилка“:** Повишено АН само в лекарския кабинет. Сърдечносъдовият риск е по-нисък спрямо постоянната хипертония.\n* **Маскирана хипертония:** Нормално АН в кабинета, но повишено в домашна среда. Рискът е сходен с този при класическата хипертония.\" id=\"note-1777402098853-1\"><span style=\"color: rgb(112, 48, 160)\">Ключови понятия</span></span></strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация на артериалната хипертония</h2><h3>Етиологична класификация</h3><ol><li><strong>Есенциална (първична):</strong> С неизяснена единична причина (около 90-95% от случаите).</li><li><strong>Симптоматична (вторична):</strong> Дължи се на конкретно заболяване (бъбречно, ендокринно и др.).</li></ol><h3>Категории според Европейската асоциация по хипертония</h3><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Категория</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Систолно (mmHg)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Диастолно (mmHg)</span></strong></td></tr><tr><td>Оптимално</td><td>&lt; 120</td><td>&lt; 80</td></tr><tr><td>Нормално</td><td>120 – 129</td><td>80 – 84</td></tr><tr><td>Високо нормално</td><td>130 – 139</td><td>85 – 89</td></tr><tr><td><strong>I степен</strong></td><td>140 – 159</td><td>90 – 99</td></tr><tr><td><strong>II степен</strong></td><td>160 – 179</td><td>100 – 109</td></tr><tr><td><strong>III степен</strong></td><td>≥ 180</td><td>≥ 110</td></tr><tr><td>Изолирана систолна</td><td>≥ 140</td><td>&lt; 90</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><p>Етиологията е многофакторна и хетерогенна, като включва:</p><ul><li><strong>Рискови фактори:</strong> Наднормено тегло, висока консумация на сол, хиподинамия, стрес и напреднала възраст.</li><li><strong>Генетична предразположеност:</strong> Играе ключова роля, като степента на унаследяване варира между <strong>35% и 50%</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><p>Патогенезата се обяснява чрез <strong>\"Мозаечната теория\"</strong>: заболяването започва с нарушение в едно звено, което впоследствие увлича останалите в \"порочен кръг\".</p><ol><li><strong>Симпатикова нервна система:</strong> Повишен симпатиков тонус<p>, водещ до вазоконстрикция.</p></li><li><strong>Ренин-ангиотензин-алдостеронова система (РААС):</strong> Задръжка на натрий и вода, <p>съчетана с повишен съдов тонус.</p></li><li><strong>Ендотелна дисфункция:</strong> Намалено производство на вазодилататори (азотен оксид) и превес на вазоконстриктори.</li><li><strong>Бъбречен механизъм:</strong> Нарушен мембранен транспорт на натрий и дефект в бъбречната екскреция.</li></ol><p>С времето хипертонията се <strong>„фиксира“</strong> вследствие на структурно съдово ремоделиране.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Клинична картина</h2><p>Хипертонията често се определя като <strong>„тих убиец“</strong>, тъй като може да протича <strong>безсимптомно</strong> в продължение на години. Приблизително 50% от засегнатите не подозират за състоянието си.</p><p><strong>Възможни симптоми:</strong></p><ul><li><strong>Неврологични:</strong> Тилно главоболие или болки в очите.</li><li><strong>Общи:</strong> Намалена работоспособност и задух.</li><li><strong>Кардиални:</strong> Опресия (притискане) в гърдите.</li></ul><p>Заболяването може да дебютира директно с тежки усложнения като <strong>инсулт или инфаркт</strong>. От съществено значение е установяването на фамилна обремененост при снемане на анамнезата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Физикално изследване при артериална хипертония</h2><p>Физикалната находка при есенциална хипертония често е бедна, като водещ признак е самото повишено АН.</p><p><strong>Сърдечносъдови находки (Есенциална хипертония)</strong></p><ul><li><strong>Акцентуиран втори тон на аортата:</strong> Дължи се на високото налягане при затваряне на аортните клапи.</li><li><strong>Четвърти сърдечен тон (Т4)&nbsp;/ Предсърден галоп:</strong> Свързан с левокамерна хипертрофия и затруднено диастолно пълнене.</li><li><strong>Сърдечен удар и пулс:</strong> Установяват се повдигащ сърдечен удар и напълнен пулс като индикатори за увеличена левокамерна маса.</li></ul><p><strong>Специфични находки (Вторична хипертония)\n</strong>При симптоматичните форми се наблюдават специфични белези:</p><ul><li><strong>Коарктация на аортата:</strong> Систоличен шум, доловим в междулопатъчното пространство (на гърба).</li><li><strong>Реновазална хипертония:</strong> Систоличен шум над проекционните места на бъбречните артерии (в коремната област).</li></ul><h3 style=\"color: rgb(112, 48, 160) !important\">Диагностичен план: Програма „Минимум“</h3><p>Основната цел е оценка на увреждането на таргетните органи (сърце, очи, бъбреци, мозък), определяне на стадия и изключване на вторична хипертония.</p><ol><li><strong>Лабораторни изследвания:</strong> ПКК, СУЕ, урина (относително тегло, протеин, седимент), електролити и липиден профил.</li><li><strong>ЕКГ:</strong> За установяване на левокамерна хипертрофия. Основен критерий е <strong>индексът на Соколов-Лайон &gt; 35 mm</strong> (S<sub>V1 </sub>+ R<sub>V5/V6</sub>).</li><li><strong>Ехокардиография:</strong></li><ul><li><strong>Концентрична хипертрофия:</strong> Симетрично задебеляване на септума и задната стена на ЛК с увеличена мускулна маса.</li><li><strong>Диастолна дисфункция:</strong> Най-ранният белег; повишена ригидност на камерата и затруднено пълнене.</li><li><strong>Дилатация на ляво предсърдие:</strong> Индиректен белег за хронично повишено налягане.</li><li><strong>Систолна функция:</strong> Първоначално запазена (хиперкинетизъм), в напреднал стадий — понижена фракция на изтласкване.</li><li><strong>Аорта:</strong> Възможна дилатация на аортния корен.</li></ul><li><strong>Изследване на очни дъна (Офталмоскопия):</strong></li><ul><li><strong>I стадий (Ангиопатия):</strong> Съдов спазъм и леко усилени светлинни рефлекси.</li><li><strong>II стадий (Ангиосклероза):</strong> Артериално стеснение, намалено кръвонапълване и <strong><span class=\"editor-note\" data-note=\"Притискане на вена от склерозирала артерия.\" id=\"note-1777407261762-2\">симптом на Гън</span></strong>.</li><li><strong>III стадий (Ретинопатия):</strong> Кръвоизливи, оток на папилата, дегенерация, риск от отлепване на ретината и атрофия на зрителния нерв.</li></ul><li><strong>Ехография на коремни органи:</strong> Оценка на бъбречна паренхима и надбъбречни жлези.</li><li><strong>Рентгенография на сърце и бял дроб:</strong></li><ul><li>Закръглен сърдечен връх и разширена лява камера.</li><li><p>Аортната дъга е разширена, удължена и разгъната.</p></li><li>При сърдечна недостатъчност: Белодробен застой.</li></ul></ol><h3 style=\"color: rgb(112, 48, 160) !important\">Диагностичен план: Програма „Максимум“</h3><p>Прилага се при съмнение за симптоматична (вторична) хипертония и включва тясно специализирани изследвания според подозираната етиология:</p><ul><li><strong>Бъбречни заболявания:</strong> Креатининов клирънс, количествено изследване на протеинурия, урография, бъбречна биопсия, реновазография и изследване на ренин.</li><li><strong>Ендокринни причини:</strong> Измерване на плазмени катехоламини (адреналин, норадреналин), кортизол, алдостерон и плазмена ренинова активност (ПРА). Използва се и КТ на надбъбречните жлези.</li><li><strong>Съдови аномалии:</strong> Аортография (при съмнение за коарктация на аортата или аортоартериит).</li><li><strong>ЯМР:</strong> Счита се за най-точния метод за прецизно определяне на лявокамерната мускулна маса.</li></ul><h3 style=\"color: rgb(112, 48, 160) !important\">Ригидност на големите артерии</h3><p>Важен показател за прогнозата е скоростта на пулсовата вълна (<strong>PWV</strong>). Пулсовата вълна се движи по-бързо през ригидни съдове. Стойности на <strong>PWV &gt; 10 m/s</strong> показват значими функционални нарушения на аортата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Протичане на артериалната хипертония</h2><p>Характерът на заболяването варира според контрола на артериалното налягане и скоростта на увреждане на таргетните органи</p><ul><li><strong>Обичайно протичане:</strong> Постига се добър медикаментозен контрол без кризи. С времето може да се наложи добавяне на нови медикаменти за поддържане на терапевтичния ефект.</li><li><strong>Затегнато протичане:</strong> Труден контрол, съпроводен с чести пикове на АН и хипертонични кризи.</li><li><strong>Малигнена хипертония:</strong> Изключително агресивна форма с морфологичен субстрат <strong>фибриноидна артериоларна медионекроза</strong>. Характеризира се с ранни усложнения и често фатален изход.</li><li><strong>Хипертонична криза:</strong> Рязко покачване на АН (систолно <strong>&gt; 220 mmHg</strong> / диастолно <strong>&gt; 130 mmHg</strong>). Съпровожда се от оплаквания от страна на ЦНС, сърцето и храносмилателната система.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Стадии на артериалната хипертония</h2><p>Стадирането се базира на обективното засягане на таргетните органи (сърце, очи, бъбреци, мозък):</p><ul><li><strong>I стадий (Функционален):</strong> Липсват органични промени. Единствената находка може да бъде ангиопатия в очните дъна.</li><li><strong>II стадий (Органичен):</strong> Налице са структурни органни промени (напр. левокамерна хипертрофия), но без нарушение на тяхната функция.</li><li><strong>III стадий (Декомпенсация):</strong> Налице е органна недостатъчност.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Засягане на таргетните органи</h2><p>При прогресия на заболяването се наблюдават следните патологични промени:</p><ul><li><strong>Сърце:</strong> Левокамерна хипертрофия, сърдечна недостатъчност, коронарна болест, дисекация на аортата.</li><li><strong>Очни дъна:</strong> Ангиопатия, ангиосклероза, ретинопатия (до отлепване на ретината).</li><li><strong>Бъбреци:</strong> Микроалбуминурия, протеинурия, хронична бъбречна недостатъчност.</li><li><strong>Мозък:</strong>&nbsp;</li><ul><li><i>Симптомни: </i>Инсулт, транзиторни исхемични атаки, деменция.</li><li><em>Безсимптомни (открити с ЯМР):</em> Лакунарни инфаркти, микрохеморагии, мозъчна атрофия и хиперинтензивни зони в бялото вещество.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Формулиране на диагнозата</h2><p>Пълната диагноза на артериалната хипертония задължително трябва да включва следните компоненти:</p><ol><li><strong>Форма:</strong> Есенциална (първична) или вторична (симптоматична).</li><li><strong>Степен:</strong> Според стойностите на АН (I, II или III степен).</li><li><strong>Стадий:</strong> Според органните увреждания (I, II или III стадий).</li><li><strong>Протичане:</strong> Обичайно, затегнато или малигнено.</li><li><strong>Усложнения:</strong> Описват се конкретните засягания (напр. инсулт, ИБС, ХБН).</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 14. Хипертонична болест - лечение.</h1><p><strong>Цел на лечението:</strong> Нормализиране на АН, спиране прогресията на заболяването, намаляване на усложненията и удължаване на живота. Понижение на САН с 10 mmHg или на ДАН с 5 mmHg намалява риска от големи сърдечно-съдови събития с <strong>20%</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>1. Промяна в начина на живот</h2><p>Тези мерки са задължителни за всички пациенти и могат да бъдат достатъчни при лека хипертония с нисък риск.</p><ul><li><strong>Ограничаване на солта:</strong> До <strong>5.0 g сол</strong>&nbsp;дневно.</li><li><strong>Редукция на теглото:</strong> Целеви BMI <strong>20-25 kg/m<sup>2</sup></strong>.</li><li><strong>Ограничаване на алкохола:</strong> До 40 g дневно за мъже и 20 g за жени.</li><li><strong>Физическа активност:</strong>&nbsp;Поне 30 мин. динамично натоварване (бягане, плуване, колоездене) през повечето дни от седмицата.</li></ul><h2>2. Медикаментозно лечение</h2><p>Броят медикаменти се определя от тежестта на АХ и от сърдечно съдовия риск (ССР). При лека хипертония и нисък ССР се започва с <strong>монотерапия</strong>, докато при по-тежки форми се стартира с <strong>комбинирана </strong>терапия.</p><h3>Основни групи антихипертензивни средства</h3><ol><li><strong>АСЕ инхибитори (АСЕИ):</strong> (<em>Enalapril, Ramipril, Perindopril</em>) – Подходящи за начална терапия; удължават живота и предпазват бъбреците и сърцето.</li><li><strong>Ангиотензин-рецепторни блокери (АРБ):</strong> (<em>Telmisartan, Valsartan</em>) – Алтернатива на АСЕИ, без страничния ефект \"кашлица\".</li><li><strong>Калциеви антагонисти (КА):</strong> (<em>Amlodipin, Verapamil</em>) – С най-голям ефект при превенция на мозъчен инсулт.</li><li><strong>Бета-блокери (ББ):</strong> (<em>Bisoprolol, Nebivolol, Metoprolol</em>) – Не са за начална терапия при неусложнена АХ; прилагат се при ИБС, сърдечна недостатъчност и левокамерна хипертрофия.</li><li><strong>Диуретици:</strong> (<em>Indapamid, Hydrochlorthiazid, Chlortalidon</em>) – Потенцират ефекта на АСЕИ/АРБ; подходящи при сърдечна недостатъчност. Поради <span class=\"editor-note\" data-note=\"Неблагоприятните последици, като диселектролитемия, дислипидемия, нарушен глюкозен толеранс прави диуретиците медикаменти, които не са подходящи за начална терапия\" id=\"note-1775459613266-0\">неблагоприятните</span> си ефекти не се препоръчват за начална терапия.</li></ol><h3>Други групи</h3><ul><li><strong>Централно действащи (<span class=\"editor-note\" data-note=\"Чрез стимулиране на централните а рецептори се намалява активността на СНС.\" id=\"note-1775459726165-1\">α-агонисти</span>):</strong> <em>Methyldopa</em> (избор при бременност), <em>Clonidine</em> (при резистентна АХ).</li><li><strong>Имидазолинови агонисти:</strong> <em>Moxonidine, Rimenidine</em>&nbsp;(намаляват симпатиковия тонус, подобряват инсулиновата чувствителност).</li><li><strong><span class=\"editor-note\" data-note=\"Те са ефективни поради изразения вазодилатативен ефект, но **ортостатичната ****хипотония **ограничава тяхното приложение. Алфа блокерите са метаболитно неутрални и могат да бъдат включвани в разширени схеми за лечение на рефрактерна хипертония В настоящият момент Doxazosin се използва при лечение хипертрофия на простата.\" id=\"note-1775459771709-2\">Алфа-блокери</span>:</strong> <em>Doxazosin</em> (използва се и при хипертрофия на простатата), <i>Prazosin, Terazosin</i>.</li><li><strong>Директни ренинови инхибитори:</strong> <em>Aliskiren</em>.</li></ul><h2>3. Стратегия на лечение</h2><p>Медикаментозното лечение започва <strong>незабавно при всички високорискови пациенти</strong>, докато при първа степен хипертония с нисък риск се допуска 3-месечен опит за корекция чрез промяна в начина на живот преди включване на терапия. При високо нормално налягане медикаменти се обсъждат само при много висок риск и липса на ефект от немедикаментозните мерки.</p><p>Предпочита се <strong>фиксирана комбинация</strong> (две или три съставки в едно хапче) за по-добър комплаянс.</p><ol><li><strong>Стъпка 1:</strong> Двойна комбинация (АСЕИ<strong>/</strong>АРБ <strong>+</strong> Калциев антагонист<strong>/</strong>Диуретик).</li><li><strong>Стъпка 2:</strong> Тройна комбинация (АСЕИ<strong>/</strong>АРБ <strong>+</strong> Калциев антагонист <strong>+ </strong>Диуретик).</li><li><strong>Стъпка 3:</strong> При резистентна хипертония се добавя <em>Spironolactone</em>, Бета-блокер или Алфа-блокер.</li></ol><h2>4. Инструментални методи</h2><p>Прилагат се при <strong>резистентна</strong> (неповлияваща се от 3 лекарства) или <strong>рефрактерна</strong> (неповлияваща се от 5+ лекарства) хипертония.</p><ul><li><strong>Ренална симпатикова денервация:</strong> Премахване на симпатиковите нервни окончания в бъбречните артерии чрез катетър, използващ радиофреквенция или ултразвук.</li><li><strong>Каротидна барорецепторна стимулация:</strong> Имплантируемо устройство за регулиране на АН чрез барорецепторите.</li></ul><h2>5. Таргетни стойности</h2><ul><li><strong>САН:</strong> Цел &lt; 130 mmHg (но не под 120 mmHg).</li><li><strong>ДАН:</strong> Цел 70 – 79 mmHg.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение на специални групи пациенти</h2><p>Стратегията при тези пациенти изисква индивидуален подход, съобразен с придружаващите заболявания и специфичния сърдечно-съдов риск (ССР).</p><h3>1. Захарен диабет</h3><p>Високорискова група, при която АН трябва да се поддържа <strong>&lt; 140/80 mmHg</strong> (оптимално <strong>130/80</strong>, но не под 120 mmHg систолно).</p><ul><li><strong>Медикаменти:</strong> Блокерите на РААС (<strong>АСЕИ&nbsp;</strong>и <strong>АРБ</strong>) са задължителни поради техния <strong>антипротеинуричен</strong> и <strong>нефропротективен </strong>ефект.</li><li><strong>Подход:</strong> Често е необходима комбинация от два или повече медикамента + статини за контрол на общия ССР.</li></ul><h3>2. Възрастни пациенти (над 65+)</h3><p>При тази възрастова група зачестява изолираната систолна хипертония. Целта е САН 130–139 mmHg (под 140/90 mmHg).</p><ul><li><p><strong>Подход: </strong>Започва се с ниски дози и бавно повишаване поради по-чести странични ефекти.</p><br></li><li><p><strong>Труден контрол: </strong>Често са нужни 2 или повече медикамента. Ако трикомпонентна терапия (с диуретик) не свали САН под 160 mmHg, се акцентира върху останалите рискови фактори.</p><br></li><li><p><strong>Безопасност: </strong>АН задължително се мери и в <strong>изправено положение </strong>поради риск от <strong>ортостатична хипотония</strong>.</p></li></ul><h3>3. Бъбречна недостатъчност</h3><p>Основните цели са <strong>стриктен контрол на АН</strong> и <strong>редукция на протеинурията</strong> (ключов маркер за риск). Поради изключително високия СС риск често се прилага интегриран подход със статини и антиагреганти.</p><ul><li><p><strong>Избор</strong>: АСЕИ и АРБ са водещи за нефропротекция, тъй като потискат локалната РААС и гломеруларната хипертензия.</p><br></li><li><p><strong>Ефект: </strong>Първоначално леко повишение на креатинина е допустимо и има добра дългосрочна прогноза.</p></li><li><p><strong>Комбинация</strong>: Обикновено са нужни няколко медикамента, често включително бримкови диуретици.</p></li><li><p><strong>Контрол</strong>: Проследяването на <strong>микроалбуминурията </strong>е задължително за оценка на терапевтичния успех.</p></li></ul><h3>4. Мозъчно-съдови заболявания</h3><p>Лечението е критично за превенция на повторен инсулт или ТИА, като е доказано ефективно дори при пациенти с кръвно налягане в горни граници на нормата.</p><ul><li><strong>Цел:</strong> &lt; 130/80 mmHg (<p>при добра поносимост), но не по-ниско от 120/70 mmHg.</p></li><li><strong>Медикаменти:</strong> Най-подходящи са <strong>КА, АСЕИ и АРБ</strong>, тъй като понижават централното АН.</li></ul><h3>5. Сърдечна недостатъчност</h3><ul><li><strong>Терапия:</strong> Използват се <strong>АСЕ инхибитори</strong>/<strong>АРБ</strong>, <strong>бета-блокери</strong> и <strong>алдостеронови антагонисти</strong>, прибавени към <strong>диуретици</strong>.</li><li><strong>Специфики</strong>: Калциевите антагонисти се избягват, освен при нужда за контрол на стенокардия. При диастолна СН са подходящи ББ и КА (верапамилов тип).</li><li><strong>Прогноза</strong>: Редукцията на ЛК хипертрофия е ключова и се постига от всички антихипертензивни групи.</li></ul><h4>6. Исхемична болест на сърцето</h4><ul><li><strong>След инфаркт:</strong> Ранното включване на <strong>ББ</strong>, <strong>АСЕИ </strong>или <strong>АРБ </strong>значително намалява риска от повторен инцидент и смърт.</li><li><strong>Хронична ИБС:</strong> Полза носи всяко понижаване на АН, като често се използват и калциеви антагонисти за контрол на симптомите.</li></ul><h4>7. Предсърдно мъждене</h4><ul><li><strong>Превенция:</strong> <strong>АСЕИ </strong>и <strong>АРБ </strong>намаляват рецидивите и появата на предсърдно мъждене чрез благоприятно ремоделиране на лявото предсърдие.</li><li><strong>Контрол на честотата: </strong>За пациенти с хронично предъсрдно мъждене са подходящи <strong>ББ </strong>и <strong>КА </strong>(верапамил/дилтиазем).</li></ul><h3>8. Хипертония и бременност</h3><p><strong>Мерки и профилактика: </strong>Ограничаване на <strong>солта </strong>и <strong>кафето</strong>. \nПри риск от прееклампсия: <strong>Аспирин </strong>между 12-та и 36-та седмица.</p><ul><li><strong>Безопасни:</strong> <strong>Метилдопа</strong>, Лабеталол, Калциеви антагонисти.</li><li><strong>Забранени:</strong> <strong>АСЕИ, АРБ и ренинови инхибитори</strong> (тератогенен ефект!).</li><li><strong>Кризи:</strong> Лабеталол, Никардипин, венозни нитрати; Магнезиев сулфат за профилактика на еклампсия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Резистентна хипертония</h2><p><strong>Дефиниция:</strong> АН остава <strong>&gt; 140/90 mmHg</strong>, въпреки приложението на <strong>три групи</strong> медикаменти (единият от които е <strong>диуретик</strong>) в оптимални дози.</p><h3>Псевдорезистентност (да се изключи първо!)</h3><ul><li><strong>Хипертония на „бялата престилка“</strong>: Високо АН само в кабинета.</li><li><strong>Лош комплаянс: </strong>Пациентът не пие лекарствата (поради странични ефекти, цена или деменция).</li><li><strong>Грешки при измерването: </strong>Изразена калциноза на артерията (особено при възрастни) или неподходящ маншет.</li><li><strong>Лекарствени влияния:</strong> Прием на <strong>НПВС</strong>, кортикостероиди, контрацептиви, симпатикомиметици (капки за нос), наркотици или цитостатици.</li><li><strong>Придружаващи фактори</strong>: Сънна апнея, затлъстяване, алкохолизъм и прекомерен прием на сол (водещ до висок плазмен обем).</li></ul><h3>Поведение при реална резистентност</h3><ol><li><strong>Изключване на вторична хипертония</strong> (бъбречна, ендокринна).</li><li><strong>Оптимизация на диуретика:</strong> <p>Редукция на солта и увеличаване дозата на диуретика (или преминаване към бримков).</p></li><li><strong>Добавяне на 4-та линия:</strong> Ниски дози <strong>Спиронолактон</strong> (алдостеронов антагонист) или Еплеренон. Може да се добави и Доксазозин.</li><li><strong>Инструментално лечение:</strong> Ренална симпатикова денервация или стимулация на каротидния синус (барорецепторите).</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 15. Хипертонична криза – определение и лечение.</h1><p>Хипертоничната криза е критично състояние, характеризиращо се с рязко покачване на артериалното налягане (АН), обикновено с <strong style=\"color: rgb(31, 41, 55)\">диастолно налягане над 140 mmHg</strong>, което застрашава или вече уврежда таргетните органи.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинични варианти</h2><ol><li><strong>Неотложна (Hypertensive Emergency):</strong> Налице е остро, животозастрашаващо увреждане на органите. Изисква <strong>незабавно</strong> хоспитализиране и понижаване на АН с <strong>парентерални (венозни)</strong> средства.</li><li><strong>Спешна (Hypertensive Urgency):</strong> Значително повишено АН, но <strong>без</strong> данни за остро органно увреждане. Налягането може да се понижи в рамките на няколко часа с орални медикаменти.</li><li><strong>Акцелерирана (малигнена) хипертония:</strong> Характеризира се с папиларен едем (оток на зрителния нерв), хеморагии и ексудати в очните дъна.</li><li><strong>Хипертензивна енцефалопатия:</strong> Внезапно покачване на АН със силно главоболие и огнищна неврологична симптоматика, която е <strong>реверзибилна</strong> (изчезва при нормализиране на АН).</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Списък на неотложните състояния</h2><ul><li><p>Хипертонична енцефалопатия.</p><br></li><li>Хипертонична левокамерна сърдечна недостатъчност (белодробен оток).</li><li>Хипертония с миокарден инфаркт.</li><li><p>Хипертония с нестабилна стенокардия.</p><br></li><li>Хипертония и дисекация на аортата.</li><li>Тежка хипертония, свързана със субарахноидна хеморагия или мозъчносъдов инцидент.</li><li>Криза, свързана с феохромоцитом.</li><li><p>Хипертония периоперативно.</p><br></li><li>Тежка прееклампсия или еклампсия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение на неотложни хипертонични кризи</h2><p>При неотложни състояния целта е бърза, но контролирана редукция на АН в условията на интензивно отделение.</p><h3>Общи принципи и поведение</h3><ul><li><strong>Хоспитализация:</strong> Задължително в спешно/интензивно отделение с постоянен мониторинг на АН и осигурен венозен път.</li><li><strong>Темп на понижаване:</strong> Поради риск от церебрална исхемия (поради нарушена авторегулация), АН <strong>не трябва</strong> да се сваля с повече от <strong>25%</strong> от изходното в първите часове.</li><li><strong>Целева стойност:</strong> Диастолно АН около <strong>110 mmHg</strong>.</li></ul><h3>Специални групи пациенти</h3><ul><li><strong>Възрастни и след исхемичен инсулт:</strong> Ако АН е &gt; 220/120 mmHg, редукцията е само <strong>10-15%</strong>.</li><li><strong>Неврологично влошаване:</strong> При поява на нови симптоми се изисква спешна <strong>КАТ на глава</strong> и лечение на мозъчния оток с осмотични диуретици (<strong>Manitol</strong>) и венозен <strong>Furosemid</strong>.</li></ul><h3>Парентерални медикаменти (Приложими в България)</h3><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Медикамент</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Дозировка</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Клинични бележки</span></strong></td></tr><tr><td><strong>Nitropruside</strong></td><td>0.25 – 10 µg/kg/min</td><td><p><strong>Средство на избор </strong>при критични състояния, което изисква строг мониторинг поради риск от рязко спадане на АН. Ефектът му е мигновен, но изчезва минути след спиране на инфузията. Важно е да се следи за интоксикация с неговия метаболит тиоцианат.</p></td></tr><tr><td><strong>Nitroglycerin</strong></td><td>1 – 5 mg/час (инфузия)</td><td>Отличен при <strong>ИБС</strong>. Внимание: може да повиши вътречерепното налягане. Бърз ефект има и при сублингвалното му приложение.</td></tr><tr><td><strong>Furosemide</strong></td><td>20 – 40 mg i.v. струйно</td><td>Диуретик. Може да се повтори след 1 час при липса на ефект.</td></tr><tr><td><strong>Metoprolol</strong></td><td>5 mg i.v. (амп.)</td><td>Подходящ при тахикардия, хиперкинетизъм, дисекация на аортата и мозъчни хеморагии.</td></tr><tr><td><strong>Enalaprilat</strong></td><td>1.25 mg i.v. (амп.)</td><td>АСЕ-инхибитор за венозно приложение на всеки 6 часа.</td></tr><tr><td><strong>Clonidine</strong></td><td>0.15 mg (амп.)</td><td>Бавно венозно или мускулно приложение.</td></tr><tr><td><strong>Verapamil</strong></td><td>5 mg i.v. (амп.)</td><td>Калциев антагонист; влиза в съображение при специфични индикации.</td></tr></tbody></table><h3>Важно предупреждение</h3><p><strong>Никога не забравяйте:</strong> Усложнения (инсулт, инфаркт) могат да настъпят не само от самото високо налягане, но и от прекалено <strong>рязкото му спадане</strong> под действието на медикаментите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center; color: rgb(88, 129, 87)\">Тема 16. Симптоматична артериална хипертония – класификация, лечение.</h1><p>Симптоматичните хипертонии са вторични състояния, при които повишеното артериално налягане е следствие от конкретно първично заболяване на друг орган или система.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>1. Бъбречни хипертонии</h2><p>Бъбреците са най-честият източник на вторична хипертония. Те се разделят на две основни подгрупи:</p><h3>Ренопаренхимни хипертонии</h3><p>Дължат се на увреждане на самия бъбречен паренхим. Това е най-честата форма на симптоматична хипертония.</p><ul><li><strong>Причини:</strong> Гломерулонефрити (80% от случаите протичат с АХ), хроничен пиелонефрит (40-60%), диабетна гломерулосклероза (50-80%), поликистоза на бъбреците (80-90%).</li><li><strong>Патогенеза:</strong> Повишена активност на системата Ренин-Ангиотензин-Алдостерон (РААС), задръжка на натрий и вода, намаляване на бъбречните вазодилататори.</li><li><strong>Характеристика:</strong> АХ обикновено е умерена, но в 15% от случаите може да протече като малигнена. Често прогресира към хронична бъбречна недостатъчност (ХБН).</li></ul><h3>Реновазална хипертония</h3><p>Дължи се на стеноза на едната или двете бъбречни артерии.</p><ul><li><strong>Етиология:</strong> Атеросклероза (при възрастни), фибромускулна дисплазия (при млади), емболия, тромбоза или аневризма.</li><li><strong>Патогенеза:</strong> Намаленият кръвоток към бъбрека активира мощно РААС.</li><li><strong>Клинични белези:</strong> Остро начало, млада възраст, липса на фамилна обремененост и резистентност към стандартно лечение.&nbsp;<p>Преобладава симптоматиката от ЦНС.</p></li><li><strong>Аускултация:</strong> При 50-60% от болните се чува <strong>систоло-диастолен шум</strong> в епигастриума или латерално от него.</li><li><strong>Лаборатория:&nbsp;</strong><p>Повишен </p><p>хематокрит, повишен натрий и намален калий в плазмата, повишена плазмена ренинова ак</p><p>тивност и плазмения алдостерон.</p></li><li><strong>Диагноза:</strong> Аортография и реновазография (златен стандарт).</li><li><strong>Лечение:</strong> Ренална перкутанна ангиопластика или хирургична реваскуларизация.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>2. Ендокринни хипертонии</h2><h3>Феохромоцитом</h3><p>Тумор на хромафинната тъкан (най-често в медулата на надбъбрека), който произвежда адреналин и норадреналин. Клиничните прояви възникват при освобождаване на катехоламините в циркулацията, провокирано спонтанно или от външни фактори (физическа активност, палпация, анестезия).</p><ul><li><strong>Клинични форми:</strong>&nbsp;</li><ul><li><strong>Пристъпна форма (1/3):</strong> Внезапно и рязко покачване на АН,&nbsp;<p>придружено от страх, палпитации, изпотяване, бледност, тремор, силно главоболие и риск от инфаркт или инсулт. Продължителност: 15 мин – 1 час.</p></li><li><strong>Перманентна форма (1/3):</strong> Постоянно високо АН.</li></ul><ul><li><strong>Смесена форма:</strong> Трайно високо АН с добавени <p>пристъпни кризи.</p></li></ul></ul><p><strong>Диагностика</strong>: Повишени катехоламини в плазмата и урината; локализация чрез ехография, сцинтиграфия, КТ или ЯМР.</p><h3><span class=\"editor-note\" data-note=\"**Забележка:** Някои източници дефинират синдрома на Кон като първичен хипералдостеронизъм независимо от причината, докато други уточняват, че това название се отнася конкретно за алдостероном (аденом).\" id=\"note-1775419386143-0\">Хипералдостеронизъм (Синдром на Conn)</span></h3><ul><li><strong>Етиология</strong>:&nbsp;<p>Билатерална хиперплазия (60%) или алдостероном (аденом – 30%).</p></li></ul><ul><li><strong>Патогенеза:</strong> <p>предизвиква задръжка на натрий и вода (обемен тип хипертония) и калийуреза.</p></li><li><p><strong>Биохимия</strong> Хипертония + Хипокалиемия + Ниска плазмена ренинова активност + Повишен плазмен алдостерон.</p><br></li><li><strong>Симптоми:</strong>&nbsp;Мускулна слабост, полиурия (поради хипокалиемията), стабилна и умерена хипертония.</li></ul><h3>Хиперглюкокортицизъм (Болест и Синдром на Кушинг)</h3><p>Дължи се на повишена секреция на кортизол от:</p><ul><li><p>Аденом на предния дял на хипофизата (<strong>болест на Иценко-Кушинг</strong>) с увеличена секре</p><p>ция на АКТХ.</p><br></li><li><p>Доброкачествен или злокачествен тумор на надбъбречната кора (<strong>синдром на Кушинг</strong>).'</p></li></ul><p><strong>Патогенеза на АХ:</strong> Кортизолът води до задръжка на натрий и вода, повишен синтез на ренинов субстрат и повишена съдова чувствителност към вазопресори.</p><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-05/text-editor-images/2026/04/1775419856591-image.png &quot;width=100%&quot;)\" id=\"note-1775419859271-1\">Клинична картина</span>:</strong> Зачервено лунообразно лице, акне, централно затлъстяване, червени стрии по кожата, хирзутизъм, остеопороза, менструални нарушения, гинекомастия, адинамия и др.</p><h3>Други ендокринни причини</h3><p>Артериална хипертония може да се наблюдава и при:</p><ul><li><strong>Тиреотоксикоза:</strong>&nbsp;Повишена функция на щитовидната жлеза.</li><li><strong>Акромегалия:</strong>&nbsp;Свръхпродукция на растежен хормон.</li><li><strong>Хиперпаратиреоидизъм:</strong>&nbsp;Повишен паратхормон и калций.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>3. Сърдечно-съдови хипертонии</h2><p>Дължат се на хемодинамични нарушения в сърцето или големите съдове.</p><ul><li><strong>Коарктация на аортата:</strong> Вродено стеснение на аортната дъга, което обикновено се проявява в ранна възраст. Характерен белег е <strong>разликата в АН</strong><p>: високо на горните крайници и ниско или липсващо на долните</p></li></ul><ul><li><strong>Аортна инсуфициенция:&nbsp;</strong><p>Налице е голяма пулсова амплитуда — значително повишено систолно и много ниско (понякога до 0 mmHg) диастолно налягане.</p><br></li><li><strong>Пълен атриовентрикуларен блок (III ст.):&nbsp;</strong><p>Тежката брадикардия води до компенсаторно повишаване на ударния обем, което обуславя изолирана систолна хипертония.</p></li><li><strong>Атеросклероза на аортата:&nbsp;</strong>Намалената еластичност на съда при възрастни пациенти води до систолно повишение на АН.<strong> <br></strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>4. Неврогенни хипертонии (ЦНС)</h2><p>Възникват при нарушаване на централните регулаторни механизми на АН в мозъка.</p><ul><li><strong>Причини:</strong> Травми (комоцио, контузио), мозъчни тумори, възпаления (енцефалити, менингити).</li><li><strong>Механизъм:</strong> Повишаване на вътречерепното налягане или директна мозъчна исхемия.</li><li><strong>Диагноза:</strong> Клинична картина, офталмоскопия (откриване на застойна папила), КТ или ЯМР на мозъка.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>5. Хипертония при бременност</h2><p>Засяга около 10% от бременните и е водеща причина за майчина и фетална смъртност.</p><h3>Класификация:</h3><ol><li><strong>Предшестваща (хронична) хипертония:</strong> Налична преди 20-а г.с.</li><li><strong>Гестационна хипертония:</strong> Появява се след 20-а г.с. и изчезва до 6 седмици след раждането.</li><li><strong>Прееклампсия:</strong> Гестационна хипертония със значима <strong>протеинурия (&gt; 0.3 g/24h)</strong>.</li><li><strong>Еклампсия:</strong> Най-тежката форма — поява на гърчове на фона на прееклампсия.</li><li><strong>Некласифицируема:</strong> Когато липсват данни за АН преди 20-а г.с. (диагнозата се уточнява след 6-ата седмица постпартум).</li></ol><h3>Класификация по тежест:</h3><ul><li><strong>Лека:</strong> 140–159 / 90–109 mmHg.</li><li><strong>Тежка:</strong> ≥ 160 / 110 mmHg.</li></ul><h3>Основни рискови фактори за прееклампсия:</h3><ol><li><strong>Първо раждане:</strong> Най-висок риск при първа бременност.</li><li><strong>Възраст:</strong> <p>Рискът нараства с възрастта на родилката.</p></li><li><strong>Брой плодове:</strong> По-често при многоплодна бременност.</li><li><strong>Генетика:</strong> Фамилна предразположеност към прееклампсия.</li><li><strong>Анамнеза:</strong> Употреба на контрацептиви или предшестваща хипертония.</li></ol><h3>Патогенеза</h3><p>Развитието преминава през два етапа:</p><ol><li><strong>Дефект в плацентарната перфузия:</strong> Поради лезии на спиралните артерии или малка плацента се създава <strong>утеро-плацентарна хипоперфузия </strong>и <strong>плацентарна хипоксия</strong>.</li><li><strong>Системна реакция на майката:</strong> В отговор на хипоксията, плацентата отделя <p>фактори, увреждащи съдовия ендотел на майката</p>. Това води до&nbsp;<strong>тежка ендотелна дисфункция</strong> и изразен оксидативен стрес, които отключват хипертонията и протеинурията.</li></ol><h3>Клинична картина и усложнения</h3><ul><li><strong>Основни симптоми:</strong> Водещи са <strong>артериалната хипертония</strong> и <strong>значимата протеинурия</strong> (&gt;0.3g/24h).</li><li><strong>HELLP синдром:&nbsp;</strong><p>Хемолиза (H), повишени чернодробни ензими (EL) и ниски тромбоцити (LP).</p></li><li><strong>ДИК синдром:</strong> Дисиминирано интравазално кръвосъсирване – критично нарушение на коагулацията. <br></li></ul><h3>Еклампсия</h3><p>Еклампсията е най-тежката фаза, дефинирана като поява на <strong>гърчове</strong> на фона на прееклампсия.</p><ul><li><strong>Механизъм:&nbsp;</strong><p>Форма на <strong>хипертензивна енцефалопатия </strong>с начален реверзибилен мозъчен оток. При липса на лечение прогресира до необратима исхемия и мозъчни инфаркти.</p></li><li><strong>Честота и прогноза:</strong> Среща се при около 1 на 2000 раждания. Смъртността е висока и може да надхвърли <strong>15%</strong>.<br></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>6. Хипертония при кръвни и белодробни заболявания</h2><ul><li><strong>Полицитемия (Polycythaemia vera):</strong> Основният механизъм е <strong>повишеният вискозитет</strong> на кръвта <p>поради увеличената еритроцитна маса</p>. Това води до нарастване на периферното съдово съпротивление и съответно на АН.</li><li><strong>Анемия:</strong> При тежки анемии се наблюдава компенсаторно повишаване на сърдечния дебит, което може да доведе до предимно систолно повишение на АН.</li><li><strong>ХОББ:</strong> Хипертонията при ХОББ често е свързана с хроничната хипоксемия, която активира симпатиковата нервна система и води до вазоконстрикция. <p>Десностранната сърдечна недостатъчност (<strong>cor pulmonale</strong>) допълнително усложнява хемодинамиката.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>7. Лекарствено индуцирана хипертония</h2><p>Продължителният прием на определени групи медикаменти е доказан рисков фактор за трайно повишаване на АН:</p><ul><li><strong>Глюкокортикоиди:</strong> Причиняват задръжка на натрий и вода в организма (подобно на синдрома на Кушинг) и повишават чувствителността на съдовете към вазопресори.</li><li><strong>Орални контрацептиви:</strong> <p>Повишават риска от АХ от</p> <strong>2 до 3 пъти</strong>. <p>Естрогените в тях стимулират чернодробния синтез на ангиотензиноген, което активира системата РААС.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Рискови групи при жени</h2><p>Съществува повишен риск от развитие на артериална хипертония при жени, които имат:</p><ol><li><strong>Фамилна обремененост:</strong> Наличие на хипертония при близки роднини..</li><li><strong>Обезитас:</strong> Наднормено тегло и затлъстяване.</li><li><strong>Анамнеза за токсикоза:</strong> <p>Жени, прекарали прееклампсия или еклампсия по време на бременност, са с много по-висок риск от развитие на фиксирана хипертония по-късно в живота.</p></li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"color: rgb(112, 48, 160) !important\">Лечение ?</h2><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 17. Исхемична болест на сърцето – класификация, етиология, патогенеза, диференциална диагноза на гръдната болка.</h1><p>Исхемичната болест на сърцето (ИБС) представлява остро, подостро или хронично увреждане на сърцето, дължащо се на несъответствие между коронарния кръвоток и нуждите на миокарда. Основната причина е заболяване на коронарните артерии.</p><ul><li>Често се използва и терминът <strong>коронарна болест на сърцето</strong>.</li><li>Не се включват състояния извън коронарната патология (напр. анемия, високопланинска болест), въпреки че могат да причинят исхемия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация</h2><p>Различните клинични прояви на исхемичната болест на сърцето се обединяват от обща етиология и патогенеза, свързана със стеснение и/или запушване на коронарните съдове. Макар че болката е основният симптом, клиничните изяви могат да бъдат разнообразни, т.е. исхемията е многолика.</p><p>Следната класификация, включваща 10 клинични форми, отразява това многообразие:</p><ol><li>Миокарден инфаркт – остър, хроничен (с Q или без Q зъбец)</li><li>Стабилна стенокардия</li><li>Нестабилна стенокардия</li><li>Вазоспастична стенокардия</li><li>Слединфарктна стенокардия</li><li>Безболкова форма</li><li>Ритъмно-проводна форма</li><li>Исхемична кардиомиопатия</li><li>Внезапна сърдечна смърт</li><li>Безсимптомна форма</li></ol><p>По протичане ИБС най-общо се разделя на:</p><ul><li><strong>Остри форми</strong> – морфологичният субстрат е нестабилна коронарна плака с ерозии, разкъсване, нарушена цялост и образуване на тромбоза</li><li><strong>Хронични форми</strong> – коронарната плака е устойчива, със стабилна морфология</li></ul><p>В последните години се използва терминът <strong>остър коронарен синдром (ОКС)</strong>, който обединява острите форми на ИБС. Основен критерий, по който се разделя ОКС. е наличието на ST елевация на кардиограмата. Той се дели на две основни групи ОКС с ST елевация и ОКС без ST елевация. ОКС без ST елевация може да еволюира в три форми - остър миокарден инфаркт без Q зъбец, нестабилна стенокардия (НАП) и рядко в остър миокарден инфаркт с Q зъбец. ОКС със ST елевация може да достигне до две форми- остър миокарден инфаркт без Q зъбец и остър миокарден инфаркт с Q зъбец. <img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-21/text-editor-images/2026/04/1776790237415-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-21/text-editor-images/2026/04/1776790237415-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-21/text-editor-images/2026/04/1776790237415-image.png\" data-width=\"70\" data-align=\"left\" style=\"width: 989.8px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto 8px 0px\" data-broken-cleanup-bound=\"1\"></p><p>Въведено е и понятието <strong>хроничен коронарен синдром (ХКС)</strong>, което включва:</p><ol><li>Пациенти със суспектна коронарна болест и стабилна стенокардия и/или диспнея.</li><li>Пациенти с новопоявила се сърдечна недостатъчност или левокамерна дисфункция и суспектна коронарна болест.</li><li>Асимптоматични или симптоматични пациенти със стабилна симптоматика &lt; 1 година след ОКС или реваскуларизация.</li><li>Асимптоматични или симптоматични пациенти &gt; 1 година след начална диагноза коронарна болест или реваскуларизация.</li><li>Пациенти със стенокардия и суспектна вазоспастична или микроваскуларна болест.</li><li>Асимптоматични пациенти, при които диагнозата е поставена при скрининг изследване.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><h3>I. Атеросклероза</h3><ul><li>водеща причина за ИБС - 95%</li><li>причинява прогресивно стеснение на коронарните съдове</li></ul><h3>II. Неатеросклеротични форми</h3><ul><li>коронарен спазъм</li><li>коронарити</li><li>емболизъм</li><li>мускулен мост</li><li>дисекираща аневризма на аортата</li><li>коронарни интервенции</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Рискови фактори</h2><p>Съществуват състояния, които увеличават риска от развитие на атеросклеротичния процес и съответно на ИБС. Те се означават като рискови фактори и се разделят на модифицируеми и немодифицируеми.</p><h4>Модифицируеми рискови фактори</h4><ol><li>Артериална хипертония</li><li>Дислипидемия</li><ul><li><p>↑</p> LDL холестерол</li><li><p>↓</p> HDL холестерол</li><li><p>↑</p> триглицериди</li></ul><li>Диабет</li><li>Тютюнопушене</li><li>Психоемоционален стрес</li><li>Наднормено тегло</li><li>Прекомерна консумация на алкохол</li><li>Диетични навици с високо съдържание на мазнини</li></ol><h3>Немодифицируеми рискови фактори</h3><ol><li>Фамилност по отношение на ИБС</li><li>Прекарани предишни коронарни инциденти</li><li>Пол</li><li>Възраст</li></ol><p>Рисковите фактори с <strong>най-голяма тежест</strong> са:</p><ul><li>артериална хипертония</li><li>диабет</li><li>дислипидемия</li><li>тютюнопушене</li></ul><p>Всеки от тях самостоятелно приблизително удвоява риска от развитие на ИБС. В практиката обикновено при един пациент се наблюдава съчетание от няколко рискови фактора, което значително увеличава вероятността за развитие на заболяването. Наличието на диабет се приема като еквивалент на ИБС.</p><p>Най-разпространеният метод за оценка на риска е чрез <strong>SCORE индекс</strong>, който определя вероятността (в проценти) за развитие на ИБС в следващите 10 години. Включва пет основни показателя:</p><ul><li>пол</li><li>възраст</li><li>систолно артериално налягане</li><li>холестерол</li><li>тютюнопушене</li></ul><p>Като антирискови фактори се разглеждат мерки, които могат да намалят риска от развитие на ИБС:</p><ul><li>умерена физическа активност през повечето дни от седмицата (30–40 минути)</li><li>умерена консумация на алкохол (20 г за мъже, 10 г за жени)</li><li>ежедневна консумация на около 200 г плодове и зеленчуци</li><li>прием на риба два пъти седмично</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза</h2><p>В основата на исхемичната болест на сърцето стои <strong>несъответствие между коронарния кръвоток и метаболитните нужди на миокарда</strong>.\nТова може да възникне при:</p><ul><li>стеснение на коронарните съдове</li><li>повишени кислородни нужди на миокарда</li><li>комбинация от двата механизма</li></ul><p>Стеснението най-често е <strong>органично </strong>(<strong>атеросклеротично</strong>), като може да бъде със или без добавен коронарен спазъм. Изолираният спазъм е рядък.</p><p>Кислородните потребности на миокарда зависят от:</p><ul><li>сърдечната честота</li><li>контрактилитета</li><li>напрежението на камерната стена</li></ul><h3>Развитие на атеросклерозата</h3><p>Атеросклеротичната плака се формира в продължение на десетилетия, като началото на процеса зависи от рисковия профил на пациента.</p><p>Обикновено клиничната изява настъпва при стеснение над <strong>70%</strong>, но е възможно дестабилизиране и на по-малки стенози с последваща тромбоза и инфаркт.</p><h3>Ендотелна дисфункция</h3><p>Началото на атеросклеротичния процес е <strong>ендотелната дисфункция</strong>. Съдовият ендотел представлява активен орган, участващ в поддържането на съдовата хомеостаза, като регулира съдовия тонус, коагулацията, възпалението и пролиферацията на гладкомускулните клетки.</p><p>При това състояние доминират фактори, благоприятстващи <strong>вазоконстрикцията</strong>, <strong>прокоагулацията</strong> и <strong>възпалението</strong>.</p><p>Основните прояви включват:</p><ul><li>повишен синтез на вазоконстриктори и прокоагуланти</li><li>намален синтез на вазодилататори и антикоагуланти</li><li>експресия на адхезионни молекули</li><li>повишена експресия на рецептори за липопротеини</li><li>синтез на цитокини и растежни фактори</li><li>повишен оксидативен стрес</li><li>повишен съдов пермеабилитет</li></ul><h3>Етапи на атерогенезата\n</h3><p>Процесът протича последователно:</p><ul><li>увреждане на ендотела → ендотелна дисфункция</li><li>повишена пропускливост за LDL</li><li>задържане и модификация на липиди в съдовата стена</li><li>миграция на моноцити и Т-лимфоцити</li><li>формиране на пенести клетки</li><li>некроза и образуване на липидно ядро</li><li>пролиферация на гладкомускулни клетки</li><li>формиране на фиброзна плака</li><li>руптура или ерозия на плаката → тромбоза</li></ul><h3>Стабилна и нестабилна плака</h3><p><strong>Стабилната плака </strong>е характерна за <strong>хроничните форми</strong> и води до относително постоянна стеноза. Симптомите се появяват главно при увеличени кислородни нужди.</p><p><strong>Нестабилната плака</strong> е склонна към <strong>руптура</strong>, което води до тромбоцитна активация, тромбоза и при персистиране – до миокардна некроза. Това състояние клинично съответства на <strong>остър коронарен синдром</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Диференциална диагноза на гръдната болка</h2><p>Диференциалната диагноза трябва да следва анатомичен принцип и да включва:</p><ul><li>нестабилна стенокардия – промяна в характера на болката, по-тежко протичане, позитивни тропонини</li><li>миокарден инфаркт – болка над 20 минути, типични ЕКГ промени, Q зъбец, позитивни ензими</li><li>перикардит – болка, зависеща от дишането, облекчава се в седнало положение, перикардно триене, дифузна ST елевация, перикарден излив</li><li>плеврит – болка при вдишване, плеврално триене, възможен плеврален излив</li><li>дисекираща аневризма на аортата – <p>болката е много силна, като пробождане с нож, ирадира към гърба</p>,<p> кардиограмата е непроменена,</p> разлика <p>в пулсациите на ръцете</p>, <p>поява на аортна </p><p>инсуфециенция, трансезофагеалната ехокардиография показва характерна “двуцевка\" и типа </p><p>на дисекацията</p></li><li>гастроинтестинални причини:</li><ul><li>езофагит</li><li>панкреатит</li><li>дуоденална язва</li></ul><li>други:</li><ul><li>невралгия</li><li>панически разстройства</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 18. Исхемична болест на сърцето – хронични форми.</h1><h1>Стабилна стенокардия</h1><p>Стабилната стенокардия е <strong>пристъпна предноторакална болка</strong>, резултат от преходна миокардна исхемия, която се появява при <strong>физическо усилие </strong>и <strong>отзвучава при покой </strong>или след прием на <strong>нитроглицерин</strong>. Характерно е, че <strong>оплакванията запазват сходен характер за дълъг период от време</strong>.</p><h2>Патогенеза</h2><p>Стенокардната болка се дължи на <strong>несъответствие между кислородната доставка и потребностите на миокарда</strong>.</p><p>Основните механизми са два и често се комбинират:</p><ul><li><strong>Намалена кислородна доставка:</strong></li><ul><li>сигнификантна коронарна стеноза (най-често атеросклеротична плака)</li><li>възможен коронарен спазъм</li><li>по-къса диастола → намалено коронарно пълнене</li></ul><li><strong>Повишена кислородна консумация:</strong></li><ul><li>повишена сърдечна честота</li><li>повишен контрактилитет</li><li>увеличена левокамерна маса</li></ul></ul><p>В клиничната практика ориентир за кислородната консумация дава т.нар. двойно произведение:</p><ul><li><strong>сърдечна честота × систолно артериално налягане</strong></li></ul><p>При стабилната стенокардия атеросклеротичната плака е устойчива, което обуславя относително постоянната клинична картина.</p><h2>Клиника</h2><p>Типично за стабилната стенокардия е ретростернална болка, която се появява при физическо усилие и отзвучава при покой или след прием на нитроглицерин.</p><p><strong>Болката има характерни особености</strong>:</p><ul><li>локализация – най-често ретростернална</li><li>обхваща широка зона</li><li><strong>стягащ характер</strong></li><li>не е точкова или пробождаща</li><li>Често пациентите описват болката с типичен жест – <strong>стиснат юмрук върху гръдната кост</strong>.</li></ul><p><strong>Ирадиацията е типична</strong>:</p><ul><li>към улнарната повърхност на лявата ръка</li><li>към долната челюст</li><li>към диафрагмата</li><li>възможно към двете ръце</li><li>По-широката ирадиация насочва към по-тежка (многоклонова) коронарна болест.</li></ul><p><strong>Продължителността на болката</strong>:</p><ul><li>обикновено няколко минути</li><li>съвпада с физическото усилие</li><li>болка под 1 минута не е типична</li></ul><p><strong>Провокиращи фактори</strong>:</p><ul><li>физическо усилие</li><li>студ, вятър</li><li>хранене</li></ul><p><strong>Облекчение настъпва при</strong>:</p><ul><li>покой</li><li>нитроглицерин</li></ul><p><strong>Съпътстващи симптоми (по-рядко):</strong></p><ul><li>задух</li><li>изпотяване</li><li>гадене</li></ul><p>Стабилната стенокардия може да протече и по <strong>атипичен начин</strong>, като тези форми могат да се изявят самостоятелно или да се съчетават с типичната клинична картина:</p><ul><li><strong>Сутрешна стенокардия (феномен на „преминаване през болката“) –</strong> появява се след ставане, като през останалата част от деня пациентът може да понася по-големи усилия без оплаквания; обяснява се с включване на колатерално кръвообращение и влияние на симпатикусовия тонус</li><li><strong>Нощна стенокардия –</strong> пристъпите се появяват предимно през нощта и се свързват с промени във вегетативната нервна система</li><li><strong>Декубитална ангина –</strong> възниква при лягане, когато увеличеният венозен приток към сърцето води до повишена кислородна консумация и поява на исхемия</li><li><strong>Постпрандиална стенокардия –</strong> появява се след нахранване, поради кръвонапълване в абдоминалната област и „ефект на открадване“ от коронарното кръвообращение</li><li><strong>Стенокардия при излагане на студ –</strong> студът провокира коронарен спазъм, който допълнително намалява коронарния кръвоток и води до болка</li><li><strong>Стенокардия след пушене –</strong> също се дължи на коронарен спазъм, който усилва вече съществуващата стеноза</li><li><strong>Стенокардия след прекъсване на нитрати –</strong> наблюдава се при рязко спиране на нитратна терапия, свързана с промени в съдовия тонус и реактивност</li></ul><p>Тези форми не винаги следват типичния модел на усилие → болка → покой, което може да затрудни диагностиката.</p><h2>Класификация</h2><p>Стабилната стенокардия се класифицира в четири функционални класа (ФК) според степента на ограничение при физическо усилие:</p><ul><li><strong>I ФК</strong> – болка се появява само при физически усилия, по-големи от обичайните за пациента</li><li><strong>II ФК</strong> – болка се появява при обичайни физически усилия</li><li><strong>III ФК</strong> – болка се появява при физически усилия, по-малки от обичайните</li><li><strong>IV ФК</strong> – болка се появява в покой</li></ul><h2>Изследвания</h2><p>Диагнозата на ИБС и коронарната стеноза е труден и отговорен процес. Основен проблем е, че <strong>неинвазивните методи не винаги изключват заболяването</strong>, като е възможно всички тестове да са негативни, а коронарографията да установи значима стеноза. От друга страна, не е оправдано всички пациенти да се подлагат на инвазивно изследване.</p><h3>ЕКГ</h3><p>ЕКГ промените, насочващи към исхемия, включват:</p><ul><li>хоризонтална или бавно десцендентна ST депресия</li><li>&gt; 1 mm в стандартни отвеждания</li><li>&gt; 2 mm в прекордиални отвеждания</li></ul><p>Кардиограмата в покой и извън пристъп често е нормална.</p><h3>Холтер ЕКГ</h3><p>24-часовият Холтер ЕКГ увеличава вероятността за доказване на исхемични промени.</p><h3>Проби с натоварване</h3><p>Провеждат се чрез велоергометър или тредмил:</p><ul><li>провокират повишена кислородна консумация</li><li>положителни са при:</li><ul><li>типична стенокардна болка</li><li>сигнификантна ST депресия</li></ul></ul><h3>Стрес ехокардиография</h3><p>Повишава чувствителността на теста с натоварване, като освен ЕКГ промените се оценява и кинетиката на миокарда:</p><ul><li>хипокинезия</li><li>акинезия</li><li>дискинезия</li></ul><p>Съвременните техники (strain) позволяват по-точна оценка на исхемията.</p><h3>Медикаментозни тестове</h3><p>Прилагат се добутамин или дипиридамол:</p><ul><li>повишават кислородната консумация</li><li>провокират исхемия при наличие на стеноза</li></ul><h3>Радиоизотопна сцинтиграфия</h3><p>Метод с висока информативност, базиран на установяване на хипоперфузия. Изследването се прави по време на натоварване:</p><ul><li>дефект при натоварване → исхемия</li><li>изчезване на дефекта в покой → непълно запушване</li><li>персистиращ дефект → оклузия или цикатрикс след инфаркт</li></ul><h3>Сърдечен магнитен резонанс (CMR)</h3><p>Позволява оценка на коронарната микроваскуларна дисфункция:</p><ul><li>перфузията</li><li>глобалния и регионален контрактилитет</li><li>тъканната морфология</li><li>субендокардна и субепикардна перфузия</li><li>регионалната коронарна резистентност</li></ul><h3>Компютърна томография (КТ)</h3><p>Контрастната КТ:</p><ul><li>реконструира коронарната анатомия</li><li>използва се като неинвазивен скрининг метод</li><li>изисква ниска сърдечна честота за по-добра визуализация</li></ul><h3>Позитрон-емисионна томография (PET)</h3><ul><li>установява метаболитни промени при исхемия</li><li>възможни са хибридни изследвания с КТ</li><li>позволява оценка на структура и функция на коронарната артерия</li></ul><h3>Коронарография</h3><p>Златен стандарт за диагностика:</p><ul><li>директна визуализация на коронарните съдове</li><li>негативните неинвазивни тестове не изключват патология</li></ul><h3>FFR (Fractional Flow Reserve)</h3><p>Метод за функционална оценка на стенозата:</p><ul><li>измерва <p>съотношението между коронарното налягане, преди и след стенозата на коронарната артерия, в условия</p><p>на максимална хиперемия на миокарда, която се предизвиква медикаментозно</p></li><li><p>съотношение представлява потенциалното намаляване на коронарния поток след стенозата</p><br></li><li>стойности &lt;0.75–0.80 са патологични</li></ul><h3>Лабораторни изследвания</h3><p>Имат значение основно за оценка на риска:</p><ul><li>липиден профил</li><li>кръвна захар</li><li>CRP</li><li>хомоцистеин</li><li>креатинин</li><li>наличие на анемия</li></ul><p>Тропонините и сърдечните ензими са нормални (за разлика от нестабилна стенокардия).</p><h2>Лечение</h2><p>Целта на лечението е да се премахнат симптомите и да се удължи животът на болния.</p><h3><strong>Корекция на рисковия профил (Немедикаментозно лечение)</strong></h3><p>Промяната в начина на живот е фундаментална стъпка:</p><ul><li><strong>Отказ от тютюнопушене:</strong> Основен фактор, възможна медикаментозна подкрепа.</li><li><strong>Диета:</strong></li><ul><li>Ежедневно: 200 г плодове/зеленчуци и 30 г ядки.</li><li>Седмично: 1–2 пъти риба.</li><li>Ограничения: Сол (5–6 г/ден), алкохол (до 25 г абс. алкохол), избягване на захарни изделия.</li></ul><li><strong>Физическа активност:</strong> 30–60 мин. умерена активност ежедневно (през повечето дни).</li><li><strong>Редукция на теглото:</strong> Цел — BMI под 25 kg/m<sup>2</sup>.</li></ul><h3><strong>Медикаментозно лечение</strong></h3><p>Медикаментите трябва да:</p><ul><li><p>намаляват кислородната консумация.</p></li><li><p>подобряват коронарния кръвоток.</p></li><li><p>подобряват метаболизма в условия на исхемия.</p></li><li><p>забавят развитието на атеросклеротичния процес.</p></li><li><p>предпазват от тромботични усложнения.</p><br></li></ul><p>Медикаментите се делят на две основни групи:</p><h4><strong>1. Подобряващи симптомите (Антиангинозна терапия)</strong></h4><ul><li><strong>Стъпка 1:</strong> Бета-блокери (ББ) или Калциеви антагонисти (КА).</li><li><strong>Стъпка 2:</strong> Комбинация от ББ и дихидропиридинови КА.</li><li><strong>Стъпка 3:</strong> Добавяне на дългодействащ нитрат.</li><li><strong>При резистентност:</strong> Добавяне на Ранолазин или Триметазидин.</li><li><strong><p>При невъзможност да се забави сърдечната честота</p>:</strong> Добавяне на Ивабрадин.</li></ul><h4><strong>2. Подобряващи прогнозата (Удължаване на живота)</strong></h4><ul><li><strong>Антиагреганти:</strong></li><ul><li><strong>Аспирин:</strong> Основен медикамент.</li><li><strong>Клопидогрел:</strong> При пациенти с мозъчно-съдова болест или непоносимост към аспирин.</li><li><strong>Двойна антиагрегантна терапия (ДАТ):</strong> Задължителна при стентирани пациенти (обикновено за 6 месеца). При висок исхемичен риск се комбинира аспирин с втори агент (Тикагрелор, Празугрел, Ривароксабан и др.).</li></ul><li><strong>Статини:</strong> Препоръчват се при всички. Целта е достигане на таргетни нива на LDL-холестерол. При нужда се добавят Езетемиб или PCSK9 инхибитори.</li><li><strong>АСЕ-инхибитори:</strong> Подходящи при съпътстваща сърдечна недостатъчност, хипертония или диабет.</li></ul><h3><strong>Реваскуларизация (Инвазивно лечение)</strong></h3><p>Прилага се чрез балонна ангиопластика със стентиране (PCI) или байпас хирургия (CABG).</p><h4>Индикации за реваскуларизация:</h4><ol><li><strong>Симптоматични:</strong> При стеноза със стенокардия, резистентна на медикаменти.</li><li><strong>Прогностични (за удължаване на живота):</strong></li><ul><li>Стеноза на ствол на лява коронарна артерия &gt; 50%.</li><li>Проксимална стеноза на LAD (лява предна низходяща артерия) &gt; 50%.</li><li><p>Дву или триклонова болест над 50%</p> със значително намалена фракция на изтласкване (ФИ &lt; 35%).</li><li>Голяма зона на исхемия (<span style=\"text-wrap-mode: nowrap\">&gt; 10%&nbsp;</span>от лява камера).</li><li>Стеноза &gt; 50% на единствено функционираща коронарна артерия.</li></ul></ol><h4>Методи и стентове:</h4><p>Предпочита се реваскуларизация с балонна ангиопластика и поставяне на стент.</p><p><strong>Видове стентове:</strong></p><ul><li><strong>BMS (Метални):</strong> Обикновени метални стентове.</li><li><strong>DES (Лекарствено освобождаващи):</strong> Намаляват риска от повторно стеснение (рестеноза).</li></ul><blockquote><strong>Важно:&nbsp;</strong>Ангиопластиката подобрява качеството на живот и симптомите, но при стабилна стенокардия не намалява смъртността.</blockquote><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Други форми на хронична исхемична болест на сърцето.</h2><h3>1. Вазоспастична стенокардия (Стенокардия на Prinzmetal)</h3><p>Водещо в патогенезата е <strong>коронарният спазъм</strong>, който обикновено не води до миокардна некроза.</p><ul><li><strong>Клинична картина:</strong> Силна болка, наподобяваща миокарден инфаркт, явяваща се често в покой, през нощта или в ранните сутрешни часове.</li><li><strong>ЕКГ находка:</strong> Типична е <strong>обратимата ST-елевация</strong>, която изчезва след пристъпа без образуване на Q-зъбец.</li><li><strong>Особености:</strong> Лабораторните маркери са негативни. Рядко се развива при напълно здрави съдове. Средство на избор за лечение са <strong>калциевите антагонисти</strong>.</li></ul><h3>2. Безболкова (тиха) форма на миокардна исхемия</h3><p>Болката не е задължителен симптом и зависи от прага на чувствителност на пациента.</p><ul><li><strong>Рискови групи:</strong> Среща се изключително често при <strong>диабетици</strong>.</li><li><strong>Диагностика:</strong> Регистрира се чрез ЕКГ (ST-депресия), най-често при <strong>24-часов Холтер ЕКГ</strong> или по време на стрес-тест с натоварване.</li></ul><h3>3. Ритъмно-проводна форма</h3><p>Основната изява на исхемията са нарушенията в ритъма и проводимостта на сърцето.</p><ul><li><strong>Прояви:</strong> Често се наблюдава предсърдно мъждене или различни степени на AV блокове.</li></ul><h3>4. Исхемична кардиомиопатия</h3><p>Развива се вследствие на дифузни промени в коронарните съдове, водещи до дистрофия на сърдечния мускул.</p><ul><li><strong>Клинична картина:</strong> Доминират проявите на <strong>застойна сърдечна недостатъчност</strong>.</li><li><strong>Обективни белези:</strong> Кардиодилатация, релативна митрална инсуфициенция и намалена помпена функция.</li></ul><h3>5. Безсимптомна форма (Латентна ИБС)</h3><p>При тези пациенти липсват оплаквания и обективни прояви на исхемия при стандартните диагностични тестове.</p><ul><li><strong>Установяване:</strong> Коронаросклерозата се открива патоанатомично при инциденти от друг характер (катастрофи и др.).</li></ul><h3>6. Слединфарктна стенокардия (Хроничен аспект)</h3><p>Разглежда се като отделна рискова форма при пациенти с прекаран миокарден инфаркт. Може да бъде стабилна или нестабилна.</p><ul><li><strong>Забележка:</strong> Ако се появи до 14 дни след инцидента, се нарича <strong>ранна</strong> слединфарктна стенокардия и се третира с повишено внимание.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Допълнение: Внезапна сърдечна смърт</h3><p>В някои случаи тя е първата и единствена изява на исхемията. Дължи се на <strong>малигнено ритъмно нарушение</strong> (камерно мъждене), често на базата на тежка коронарна патология или спазъм, без да е оформена некроза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 19. Исхемична болест на сърцето – остър коронарен синдром без ST-елевация - клинична картина, диагноза и диференциална диагноза.</h1><p>Острият коронарен синдром без ST-елевация (NSTE-ACS) включва две клинични единици: <strong>Нестабилна стенокардия</strong> и <strong>Миокарден инфаркт без ST-елевация</strong> (<strong>NSTEMI</strong>). Основната разлика между тях е наличието на биохимични маркери за миокардна некроза (<strong>тропонин</strong>) при NSTEMI.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Нестабилна стенокардия (НАП)</h2><p>Нестабилната стенокардия се дефинира като остра или подостра коронарогенна миокардна исхемия, при която <strong style=\"color: rgb(31, 41, 55)\">не се наблюдава развитие на некроза</strong>. Тя е ключов компонент от <span class=\"editor-note\" data-note=\"Включва: - Нестабилна стенокардия\n- ОКС с ST елевация - ОКС без ST елевация\" id=\"note-1776956539658-0\">Острия коронарен синдром (ОКС)</span>, заемайки мястото между стабилната исхемична болест и миокардния инфаркт. Разликата с последния е, че при НАП липсват биохимични доказателства за миокардна некроза.</p><h3>Патогенеза</h3><p>В основата на заболяването в 60-80% от случаите стои дестабилизирана атеросклеротична плака. Процесът започва с <strong>руптура</strong> или <strong>ерозия</strong> на повърхността на плаката. </p><ul><li><strong>Разкъсването</strong> позволява на циркулиращата кръв да влезе в контакт с липидната сърцевина на плаката. Тя е богата на тъканен фактор – мощен прокоагулант, който задейства коагулационната каскада и води до образуване на <strong>тромб</strong>. Този тромб запушва лумена на артерията частично или напълно.</li><li><strong>Ерозията</strong> е по-характерна за жени пушачки. Плаките, които са най-уязвими на разкъсване, имат специфични белези: тънка фиброзна шапка, голямо липидно ядро и високо съдържание на макрофаги и възпалителни инфилтрати.</li><li>При останалите 20-40% от болните причината е високостепенна стабилна <strong>стеноза</strong>, към която може да се добави коронарен <strong>спазъм</strong>. Много фактори допринасят за тази дестабилизация, включително ендотелна дисфункция, оксидативен стрес, хемодинамични промени и системно възпаление.</li></ul><h3>Клинична класификация</h3><p>Клинично НАП се проявява в няколко основни форми:</p><ol><li><strong>Новопоявила се стенокардия </strong>в рамките на един месец.</li><li><strong>Акцелерираща стабилна стенокардия</strong>.</li><li><strong>Стенокардия в покой</strong>.</li><li><strong>Ранна слединфарктна стенокардия </strong>до 14-ия ден след прекаран миокарден инфаркт.</li></ol><h3>Класификация по Браунвалд (Braunwald)</h3><p>Тази система е фундаментална за преценка на тежестта и прогнозата чрез четири групи критерии:</p><p><strong>Група I (Тежест според времето и усилието):</strong></p><ul><li><strong>I:</strong> Поява на болка само при физически усилия.</li><li><strong>II:</strong> Болка в покой, възникнала преди повече от 48 часа (подостра).</li><li><strong>III:</strong> Болка в покой, появила се през последните 48 часа (остра).</li></ul><p><strong>Група II (Обстоятелства на възникване):</strong></p><ul><li><strong>A (Вторична):</strong> <p>Поява при наличие на екстракардиални причини (анемия, хипертонична криза, температура), които повишават нуждите на миокарда от кислород.</p></li><li><strong>B (Първична):</strong> Липсват екстракардиални причини за исхемията.</li><li><strong>C (Слединфарктна):</strong> Поява до 2 седмици след остър миокарден инфаркт.</li></ul><p><strong>Група III (Интензивност на терапията):</strong></p><ul><li><strong>1:</strong> При липса на <p>предшестваща терапия.</p></li><li><strong>2:</strong> <p>При непълна терапия.</p></li><li><strong>3:</strong> При провеждана пълна антистенокардна терапия.</li></ul><p>Към диагнозата се добавя и наличието на ЕКГ промени (<strong>ST+ или ST-</strong>). Прогностично състоянието се счита за по-тежко при по-висока поредност на цифрите и буквите (например III-C-3, ST+).</p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Тежест</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">А. При наличие на екстракардиални причини</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">В. Липсват екстракардиални причини</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">С. До 2 седмици след миокарден инфаркт</span></strong></td></tr><tr><td><strong>I.</strong> Нововъзникнала тежка, само при физически усилия</td><td>I A</td><td>I B</td><td>I C</td></tr><tr><td><strong>II.</strong> В покой, подостра (без пристъп в последните 48ч)</td><td>II A</td><td>II B</td><td>II C</td></tr><tr><td><strong>III.</strong> В покой, остра (оплаквания в последните 48ч)</td><td>III A</td><td>III B</td><td>III C</td></tr></tbody></table><h3>Клинична картина</h3><p>В основата на клиничната картина стои <strong>дестабилизацията на коронарната плака</strong>, което изисква спешна хоспитализация. Анамнезата е критична за установяване на момента на промяна в симптоматиката.</p><p><strong>Основни клинични сценарии:</strong></p><ul><li><strong>Акцелерираща нестабилна стенокардия:</strong> Ескалация при известна стабилна стенокардия, изразена чрез:</li><ul><li>По-нисък праг на болката (при по-малко физическо усилие).</li><li>По-широка ирадиация на болката и увеличена продължителност.</li><li>Повишена нужда от нитроглицерин.</li></ul><li><strong>Новопоявила се нестабилна стенокардия:</strong> Първа изява на симптоми без предходна анамнеза.</li><li><strong>Слединфарктна стенокардия:</strong> Поява на болка до 14-ия ден от началото на острия миокарден инфаркт.</li><li><strong>Стенокардия в покой:</strong> Най-тежката клинична изява на НАП.</li></ul><h3>Изследвания</h3><p>Прилагат се методите за стабилна ИБС, но със строги ограничения. <strong>Пробите с натоварване (ВЕТ) са абсолютно противопоказани в острата фаза</strong> и се провеждат единствено след пълна стабилизация.</p><p>Централно място в диагностиката заема нивото на <strong>тропонините</strong>:</p><ul><li><strong>Тропонин-позитивна НАП:</strong> Индикация за задължителна коронарография и инвазивно лечение.</li><li><strong>Тропонин-негативна НАП:</strong> Консервативно поведение и провеждане на ВЕТ преди изписването, както и на контролни прегледи (след 6–12 месеца).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър миокарден инфракт без ST елевация (NSTEMI)</h2><p>ддз</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 20. Исхемична болест на сърцето – остър коронарен синдром с ST-елевация – клинична картина, диагноза и диференциална диагноза.</h1><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 21.  Алгоритъм на поведение при остър коронарен синдром без ST-елевация.</h1><p>Начало.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 22. Исхемична болест на сърцето – лечение на неусложнен остър мокарден инфаркт.</h1><p>Начало.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 23. Алгоритъм на поведение при остър коронарен синдром с ST-елевация.</h1><p>Начало.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 24. Исхемична болест на сърцето – лечение на усложнен остър миокарден инфаркт с ритъмни и проводни нарушения, с хипо и хипертония, със сърдечна недостатъчност.</h1>Начало.<style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
